function uid(){return Date.now().toString(36)+Math.random().toString(36).substr(2,5)}
function fmt(n){return isNaN(n)?'0':Math.round(Number(n)).toString()}
function fmtK(n){return n>=10000?Math.round(n/10000)+'万':fmt(n)}
function esc(s){return String(s||'').replace(/&/g,'&amp;').replace(/"/g,'&quot;').replace(/</g,'&lt;').replace(/>/g,'&gt;')}
function showToast(msg){var t=document.getElementById('toast');t.textContent=msg;t.classList.add('show');setTimeout(function(){t.classList.remove('show')},2000)}
function formatDate(ts){if(!ts)return'';var d=new Date(ts);return d.getFullYear()+'-'+String(d.getMonth()+1).padStart(2,'0')+'-'+String(d.getDate()).padStart(2,'0')+' '+String(d.getHours()).padStart(2,'0')+':'+String(d.getMinutes()).padStart(2,'0')}
function closeAllMenus(){document.querySelectorAll('.export-menu').forEach(function(m){m.classList.remove('show')})}

var S={
  currentFileId:null,files:[],recentFileIds:[],
  customerInfo:{name:'',phone:'',address:'',designer:'',designerPhone:'',plan:'luxury',date:new Date().toISOString().split('T')[0],area:''},
  rooms:[],quoteItems:[],productQuoteItems:[],
  materials:null,spaceTypes:null,
  currentPlan:'luxury',currentTheme:'dark',
  managementFeeRate:8,taxRate:3.41,garbageFee:800,protectionFee:500,
  editingRoomId:null,editingMaterialId:null,editingSpaceTypeId:null,
  watermarkEnabled:false,watermarkText:'报价专用',colWidths:{},
  msProjectName:'',msRooms:[],importSelectedFileId:null,msEditingRoomId:null,
  products:[],pdbSelectedMainCat:null,pdbSelectedSubCat:null,editingProductId:null,addProdSelectedIds:[],
  customNotes:'',bossPassword:'888888',costRates:{luxury:0.65,premium:0.60},
  dirty:false
};
function markDirty(){S.dirty=true}
function initDefaults(){if(!S.materials)S.materials=JSON.parse(JSON.stringify(DEFAULT_MATERIALS));if(!S.spaceTypes)S.spaceTypes=JSON.parse(JSON.stringify(DEFAULT_SPACE_TYPES))}

// ==================== PERSISTENCE ====================
function loadState(){try{var f=localStorage.getItem('dq_files');if(f)S.files=JSON.parse(f);var r=localStorage.getItem('dq_recent');if(r)S.recentFileIds=JSON.parse(r);var s=localStorage.getItem('dq_settings');if(s){var d=JSON.parse(s);Object.keys(d).forEach(function(k){S[k]=d[k]})}var p=localStorage.getItem('dq_products');if(p)S.products=JSON.parse(p);migrateOldData();initDefaults()}catch(e){console.error(e);initDefaults()}}
function saveSettings(){try{localStorage.setItem('dq_settings',JSON.stringify({currentPlan:S.currentPlan,currentTheme:S.currentTheme,managementFeeRate:S.managementFeeRate,taxRate:S.taxRate,garbageFee:S.garbageFee,protectionFee:S.protectionFee,watermarkEnabled:S.watermarkEnabled,watermarkText:S.watermarkText,colWidths:S.colWidths,materials:S.materials,spaceTypes:S.spaceTypes,bossPassword:S.bossPassword,costRates:S.costRates}))}catch(e){}}
function saveFilesToStorage(){try{localStorage.setItem('dq_files',JSON.stringify(S.files));localStorage.setItem('dq_recent',JSON.stringify(S.recentFileIds))}catch(e){}}
function saveProductsToStorage(){try{localStorage.setItem('dq_products',JSON.stringify(S.products))}catch(e){showToast('存储空间不足')}}
function migrateOldData(){if(S.files.length>0)return;try{var o=localStorage.getItem('decorationQuoteV3');if(o){var d=JSON.parse(o);if(d.rooms&&d.rooms.length>0){var file={id:uid(),name:'旧版报价',type:'quotation',data:{customerInfo:d.customerInfo||S.customerInfo,rooms:d.rooms||[],quoteItems:d.quoteItems||[],productQuoteItems:[]},createdAt:Date.now(),updatedAt:Date.now()};S.files.push(file);S.recentFileIds=[file.id];saveFilesToStorage();localStorage.removeItem('decorationQuoteV3')}}}catch(e){}}
function compressImage(file,maxW,quality,cb){var reader=new FileReader();reader.onload=function(e){var img=new Image();img.onload=function(){var c=document.createElement('canvas');var ratio=Math.min(maxW/img.width,1);c.width=Math.round(img.width*ratio);c.height=Math.round(img.height*ratio);c.getContext('2d').drawImage(img,0,0,c.width,c.height);cb(c.toDataURL('image/jpeg',quality))};img.src=e.target.result};reader.readAsDataURL(file)}

// ==================== FILE MANAGEMENT ====================
function createNewFile(type){checkDirty(function(){var file={id:uid(),name:type==='quotation'?'新建报价':'新建量房',type:type,data:type==='quotation'?{customerInfo:{name:'',phone:'',address:'',designer:'',designerPhone:'',plan:'luxury',date:new Date().toISOString().split('T')[0],area:''},rooms:[],quoteItems:[],productQuoteItems:[],customNotes:''}:{projectName:'',rooms:[]},createdAt:Date.now(),updatedAt:Date.now()};S.files.push(file);addToRecent(file.id);openFile(file.id);saveFilesToStorage();showToast('已创建')})}
function openFile(id){checkDirty(function(){var file=S.files.find(function(f){return f.id===id});if(!file)return;S.currentFileId=id;addToRecent(id);if(file.type==='quotation'){S.customerInfo=Object.assign({name:'',phone:'',address:'',designer:'',designerPhone:'',plan:'luxury',date:new Date().toISOString().split('T')[0],area:''},file.data.customerInfo||{});S.rooms=file.data.rooms||[];S.quoteItems=file.data.quoteItems||[];S.productQuoteItems=file.data.productQuoteItems||[];S.customNotes=file.data.customNotes||'';if(S.customerInfo.plan)S.currentPlan=S.customerInfo.plan;showView('quotation');renderCustomerInfo();renderRoomList();renderQuoteTable();renderSummary();document.getElementById('customNotes').value=S.customNotes}else{S.msProjectName=file.data.projectName||'';S.msRooms=file.data.rooms||[];showView('measurement');renderMeasurementView()}S.dirty=false;renderSidebar();saveFilesToStorage()})}
function saveCurrentFile(){if(!S.currentFileId){showSaveFileDialog();return}var file=S.files.find(function(f){return f.id===S.currentFileId});if(!file)return;file.updatedAt=Date.now();if(file.type==='quotation'){if(S.customerInfo.address)file.name=S.customerInfo.address;file.data={customerInfo:S.customerInfo,rooms:S.rooms,quoteItems:S.quoteItems,productQuoteItems:S.productQuoteItems,customNotes:S.customNotes}}else{if(S.msProjectName)file.name=S.msProjectName;file.data={projectName:S.msProjectName,rooms:S.msRooms}}S.dirty=false;saveFilesToStorage();saveSettings();renderSidebar();showToast('已保存')}
function checkDirty(callback){if(S.dirty){var r=confirm('当前文件未保存，是否保存？');if(r){saveCurrentFile();callback()}else if(r===false){S.dirty=false;callback()}}else{callback()}}
function showSaveFileDialog(){var file=S.files.find(function(f){return f.id===S.currentFileId});if(!file)return;document.getElementById('saveFileBody').innerHTML='<div class="form-group"><label>文件名称</label><input id="saveFileNameInput" value="'+esc(file.name)+'"></div>';openModal('saveFileModal')}
function confirmSaveFile(){var n=document.getElementById('saveFileNameInput').value.trim();if(!n)return;var file=S.files.find(function(f){return f.id===S.currentFileId});if(!file)return;file.name=n;file.updatedAt=Date.now();if(file.type==='quotation')file.data={customerInfo:S.customerInfo,rooms:S.rooms,quoteItems:S.quoteItems,productQuoteItems:S.productQuoteItems,customNotes:S.customNotes};else file.data={projectName:S.msProjectName,rooms:S.msRooms};closeModal('saveFileModal');saveFilesToStorage();saveSettings();renderSidebar();showToast('已保存')}
function deleteFile(id){if(!confirm('确定删除？'))return;S.files=S.files.filter(function(f){return f.id!==id});S.recentFileIds=S.recentFileIds.filter(function(r){return r!==id});if(S.currentFileId===id){S.currentFileId=null;S.dirty=false;showView('welcome')}saveFilesToStorage();renderSidebar()}
function renameFile(id){var file=S.files.find(function(f){return f.id===id});if(!file)return;var el=document.querySelector('.sf-item-name[data-id="'+id+'"]');if(!el)return;var input=document.createElement('input');input.className='file-rename-input';input.value=file.name;el.replaceWith(input);input.focus();input.select();function finish(){var v=input.value.trim();if(v&&v!==file.name){file.name=v;file.updatedAt=Date.now();saveFilesToStorage()}renderSidebar()}input.onblur=finish;input.onkeydown=function(e){if(e.key==='Enter')finish();if(e.key==='Escape')renderSidebar()}}
function addToRecent(id){S.recentFileIds=S.recentFileIds.filter(function(r){return r!==id});S.recentFileIds.unshift(id);if(S.recentFileIds.length>15)S.recentFileIds=S.recentFileIds.slice(0,15)}
function getRecentFiles(){return S.recentFileIds.map(function(id){return S.files.find(function(f){return f.id===id})}).filter(Boolean)}
function renderSidebar(){var el=document.getElementById('sidebarFileList');var recent=getRecentFiles();if(!recent.length){el.innerHTML='<div style="padding:12px;text-align:center;font-size:11px;color:var(--text-dim)">暂无文件</div>';return}el.innerHTML=recent.map(function(f){var isActive=f.id===S.currentFileId;var icon=f.type==='quotation'?'📋':'📐';return '<div class="sidebar-file-item'+(isActive?' active':'')+'" onclick="openFile(\''+f.id+'\')"><span class="sf-icon">'+icon+'</span><div class="sf-info"><span class="sf-name sf-item-name" data-id="'+f.id+'" ondblclick="event.stopPropagation();renameFile(\''+f.id+'\')">'+esc(f.name)+'</span><span class="sf-date">'+formatDate(f.updatedAt)+'</span></div><button class="sf-delete" onclick="event.stopPropagation();deleteFile(\''+f.id+'\')">×</button></div>'}).join('')}
function showView(view){document.querySelectorAll('.view').forEach(function(v){v.classList.remove('active')});var m=document.getElementById('appMain');if(view==='welcome'){document.getElementById('welcomeView').classList.add('active');m.classList.add('narrow-main')}else if(view==='measurement'){document.getElementById('measurementView').classList.add('active');m.classList.add('narrow-main')}else if(view==='quotation'){document.getElementById('quotationView').classList.add('active');m.classList.remove('narrow-main')}else if(view==='dashboard'){document.getElementById('dashboardView').classList.add('active');m.classList.remove('narrow-main')}else if(view==='boss'){document.getElementById('bossView').classList.add('active');m.classList.remove('narrow-main')}}
function onNotesChange(){S.customNotes=document.getElementById('customNotes').value;markDirty()}

// ==================== DASHBOARD ====================
function showDashboard(){
  checkDirty(function(){S.bossAuthenticated=false;renderDashboard();showView('dashboard')});
}
function renderDashboard(){
  var quoteFiles=S.files.filter(function(f){return f.type==='quotation'});
  var allItems=[];var totalRevenue=0;var totalCount=quoteFiles.length;
  quoteFiles.forEach(function(f){var d=f.data;var items=(d.quoteItems||[]).concat(d.productQuoteItems||[]);var sub=items.reduce(function(s,i){return s+(i.quantity||0)*(i.unitPrice||0)},0);totalRevenue+=sub;allItems.push({name:f.name,date:f.updatedAt,total:sub,rooms:(d.rooms||[]).length})});
  var avgValue=totalCount>0?totalRevenue/totalCount:0;
  var msFiles=S.files.filter(function(f){return f.type==='measurement'}).length;
  var totalProducts=S.products.length;
  // Monthly data
  var months={};quoteFiles.forEach(function(f){var d=f.updatedAt;var key=new Date(d).getFullYear()+'-'+String(new Date(d).getMonth()+1).padStart(2,'0');if(!months[key])months[key]={count:0,revenue:0};months[key].count++;months[key].revenue+=f.data?(f.data.quoteItems||[]).concat(f.data.productQuoteItems||[]).reduce(function(s,i){return s+(i.quantity||0)*(i.unitPrice||0)},0):0});
  var monthKeys=Object.keys(months).sort().slice(-6);
  var maxRev=Math.max.apply(null,monthKeys.map(function(k){return months[k].revenue}))||1;
  var topFiles=allItems.slice().sort(function(a,b){return b.total-a.total}).slice(0,8);
  var el=document.getElementById('dashboardView');
  el.innerHTML='<div class="dash-nav"><button class="dash-nav-btn active">📊 数据概览</button><div style="flex:1"></div><button class="btn btn-outline btn-sm" onclick="showView(\'welcome\')">返回</button></div>'+
    '<div class="dash-stats"><div class="dash-stat-card"><div class="dash-stat-icon" style="background:var(--accent-dim);color:var(--accent)">📋</div><div class="dash-stat-value">'+totalCount+'</div><div class="dash-stat-label">报价总数</div></div>'+
    '<div class="dash-stat-card"><div class="dash-stat-icon" style="background:rgba(16,185,129,0.12);color:var(--success)">💰</div><div class="dash-stat-value">¥'+fmtK(totalRevenue)+'</div><div class="dash-stat-label">报价总额</div></div>'+
    '<div class="dash-stat-card"><div class="dash-stat-icon" style="background:rgba(245,158,11,0.12);color:var(--warning)">📈</div><div class="dash-stat-value">¥'+fmtK(avgValue)+'</div><div class="dash-stat-label">平均报价</div></div>'+
    '<div class="dash-stat-card"><div class="dash-stat-icon" style="background:rgba(139,92,246,0.12);color:#8b5cf6">📦</div><div class="dash-stat-value">'+totalProducts+'</div><div class="dash-stat-label">产品数量</div></div></div>'+
    '<div class="dash-grid"><div class="dash-card"><div class="dash-card-header"><h3>月度营收趋势</h3></div><div class="dash-card-body">'+monthKeys.map(function(k){var m=months[k];var pct=Math.round(m.revenue/maxRev*100);return '<div style="margin-bottom:10px"><div style="display:flex;justify-content:space-between;font-size:12px;margin-bottom:3px"><span>'+k+'</span><span style="color:var(--text-light)">¥'+fmtK(m.revenue)+' ('+m.count+'单)</span></div><div class="dash-bar"><div class="dash-bar-fill" style="width:'+pct+'%;background:var(--accent)"></div></div></div>'}).join('')+'</div></div>'+
    '<div class="dash-card"><div class="dash-card-header"><h3>报价明细</h3><span style="font-size:11px;color:var(--text-dim)">共 '+quoteFiles.length+' 份</span></div><div class="dash-card-body" style="max-height:320px;overflow-y:auto"><table class="dash-table"><thead><tr><th>文件名</th><th>房间</th><th>金额</th><th>日期</th><th>操作</th></tr></thead><tbody>'+topFiles.map(function(f){return '<tr><td style="font-weight:500">'+esc(f.name)+'</td><td>'+f.rooms+'</td><td style="color:var(--accent);font-weight:600">¥'+fmt(f.total)+'</td><td style="color:var(--text-dim)">'+formatDate(f.date)+'</td><td><button class="btn btn-outline btn-sm" onclick="openFile(\''+quoteFiles.find(function(q){return q.name===f.name&&q.data&&quoteFiles.find(function(qq){return qq.name===f.name}).data.total===undefined?false:true}).id+'\')">打开</button></td></tr>'}).join('')+'</tbody></table></div></div></div>';
}

// ==================== BOSS DASHBOARD ====================
function openBossLogin(){
  checkDirty(function(){S.bossAuthenticated=false;
  document.getElementById('bossPwdBody').innerHTML='<div class="boss-pwd-wrap"><div class="lock-icon">🔐</div><p style="font-size:13px;color:var(--text-light);margin-bottom:16px">请输入管理密码</p><input type="password" id="bossPwdInput" placeholder="····" onkeydown="if(event.key===\'Enter\')checkBossPwd()"><div style="margin-top:14px;display:flex;gap:8px;justify-content:center"><button class="btn btn-primary" onclick="checkBossPwd()">确认</button><button class="btn btn-outline" onclick="closeModal(\'bossPwdModal\')">取消</button></div><div class="boss-pwd-hint">初始密码: 888888</div></div>';
  openModal('bossPwdModal');setTimeout(function(){var inp=document.getElementById('bossPwdInput');if(inp)inp.focus()},100)});
}
function checkBossPwd(){
  var pwd=document.getElementById('bossPwdInput').value;if(pwd===S.bossPassword){S.bossAuthenticated=true;closeModal('bossPwdModal');renderBossView();showView('boss')}else{showToast('密码错误')}
}
function renderBossView(){
  var quoteFiles=S.files.filter(function(f){return f.type==='quotation'});
  var totalRevenue=0;var totalCost=0;var rate=S.costRates[S.currentPlan]||0.65;
  var catCosts={};
  var allStats=[];
  quoteFiles.forEach(function(f){
    var d=f.data;var items=(d.quoteItems||[]).concat(d.productQuoteItems||[]);
    var sub=items.reduce(function(s,i){return s+(i.quantity||0)*(i.unitPrice||0)},0);
    var cost=sub*rate;totalRevenue+=sub;totalCost+=cost;
    allStats.push({name:f.name,date:f.updatedAt,revenue:sub,cost:cost,profit:sub-cost,margin:sub>0?((sub-cost)/sub*100):0,rooms:(d.rooms||[]).length});
  });
  var totalProfit=totalRevenue-totalCost;var totalMargin=totalRevenue>0?(totalProfit/totalRevenue*100):0;
  var avgMargin=allStats.length?allStats.reduce(function(s,a){return s+a.margin},0)/allStats.length:0;
  allStats.sort(function(a,b){return b.revenue-a.revenue});
  var plans={luxury:'奢享全案',premium:'优享精造'};
  var el=document.getElementById('bossView');
  el.innerHTML='<div style="display:flex;gap:8px;margin-bottom:16px;align-items:center;flex-wrap:wrap"><h2 style="font-size:16px;color:var(--text);display:flex;align-items:center;gap:6px">🔐 经营看板</h2><span style="font-size:11px;color:var(--text-dim)">当前方案: '+(plans[S.currentPlan]||'')+'</span><div style="flex:1"></div><button class="btn btn-outline btn-sm" onclick="showDashboard()">数据看板</button><button class="btn btn-ghost btn-sm" onclick="showView(\'welcome\')">返回</button></div>'+
    '<div class="boss-stat-row"><div class="boss-stat"><div class="label">报价总额</div><div class="value">¥'+fmtK(totalRevenue)+'</div><div class="label" style="font-size:10px;color:var(--text-dim)">共 '+allStats.length+' 份报价</div></div><div class="boss-stat"><div class="label">预估成本</div><div class="value cost">¥'+fmtK(totalCost)+'</div><div class="label" style="font-size:10px;color:var(--text-dim)">成本率 '+(rate*100)+'%</div></div><div class="boss-stat"><div class="label">预估毛利</div><div class="value profit">¥'+fmtK(totalProfit)+'</div><div class="label" style="font-size:10px;color:var(--text-dim)">综合毛利率 '+totalMargin.toFixed(1)+'%</div></div></div>'+
    '<div class="boss-config"><h4>⚙️ 成本率设置</h4><div class="boss-config-grid"><div class="boss-config-item"><label>奢享全案成本率</label><input type="number" id="bossRateLuxury" value="'+(S.costRates.luxury*100)+'" min="0" max="100" step="1" onchange="updateBossRate()">%</div><div class="boss-config-item"><label>优享精造成本率</label><input type="number" id="bossRatePremium" value="'+(S.costRates.premium*100)+'" min="0" max="100" step="1" onchange="updateBossRate()">%</div><div class="boss-config-item"><label>修改密码</label><input type="password" id="bossNewPwd" placeholder="新密码" style="width:100%"></div><div style="margin-top:8px;display:flex;gap:6px"><button class="btn btn-primary btn-sm" onclick="saveBossConfig()">保存设置</button></div></div></div>'+
    '<div class="dash-card"><div class="dash-card-header"><h3>报价利润明细</h3></div><div class="dash-card-body" style="max-height:350px;overflow-y:auto"><table class="dash-table"><thead><tr><th>文件名</th><th>房间</th><th>报价额</th><th>预估成本</th><th>毛利润</th><th>毛利率</th><th>日期</th></tr></thead><tbody>'+allStats.map(function(a){var marginColor=a.margin>=30?'var(--success)':a.margin>=20?'var(--warning)':'var(--danger)';return '<tr><td style="font-weight:500">'+esc(a.name)+'</td><td>'+a.rooms+'</td><td style="font-weight:600">¥'+fmt(a.revenue)+'</td><td>¥'+fmt(a.cost)+'</td><td style="color:var(--success);font-weight:600">¥'+fmt(a.profit)+'</td><td style="color:'+marginColor+';font-weight:700">'+a.margin.toFixed(1)+'%</td><td style="color:var(--text-dim)">'+formatDate(a.date)+'</td></tr>'}).join('')+'</tbody></table></div></div>'+
    '<div class="dash-card"><div class="dash-card-header"><h3>利润分析</h3></div><div class="dash-card-body"><div style="display:grid;grid-template-columns:repeat(3,1fr);gap:12px"><div style="text-align:center"><div style="font-size:11px;color:var(--text-dim);margin-bottom:4px">平均毛利率</div><div style="font-size:22px;font-weight:700;color:'+(avgMargin>=30?'var(--success)':'var(--warning)')+'">'+avgMargin.toFixed(1)+'%</div></div><div style="text-align:center"><div style="font-size:11px;color:var(--text-dim);margin-bottom:4px">最高单笔利润</div><div style="font-size:22px;font-weight:700;color:var(--success)">¥'+fmt(allStats[0]?allStats[0].profit:0)+'</div></div><div style="text-align:center"><div style="font-size:11px;color:var(--text-dim);margin-bottom:4px">最低毛利率</div><div style="font-size:22px;font-weight:700;color:var(--danger)">'+(allStats.length?allStats[allStats.length-1].margin.toFixed(1):'0')+'%</div></div></div></div></div>';
}
function updateBossRate(){S.costRates.luxury=(parseFloat(document.getElementById('bossRateLuxury').value)||65)/100;S.costRates.premium=(parseFloat(document.getElementById('bossRatePremium').value)||60)/100;renderBossView()}
function saveBossConfig(){updateBossRate();var newPwd=document.getElementById('bossNewPwd').value;if(newPwd&&newPwd.length>=4){S.bossPassword=newPwd;showToast('设置已保存，新密码已生效')}else if(newPwd&&newPwd.length>0){showToast('密码至少4位')}saveSettings();renderBossView();showToast('设置已保存')}

// ==================== PRODUCT DATABASE ====================
function openProductDatabase(){S.pdbSelectedMainCat=null;S.pdbSelectedSubCat=null;S.editingProductId=null;renderProductDb();openModal('productDbModal')}
function renderProductDb(){var body=document.getElementById('productDbBody');var tree='<div class="pdb-cat-tree"><div class="pdb-cat-item'+(S.pdbSelectedMainCat===null?' active':'')+'" onclick="pdbSelectCategory(null,null)">全部 ('+S.products.length+')</div>';PRODUCT_MAIN_CATEGORIES.forEach(function(mc){var count=S.products.filter(function(p){return p.mainCategory===mc.id}).length;tree+='<div class="pdb-cat-main">'+mc.icon+' '+mc.name+' ('+count+')</div><div class="pdb-sub-list">'+mc.subcategories.map(function(sc){var sc2=S.products.filter(function(p){return p.mainCategory===mc.id&&p.subCategory===sc.id}).length;return'<div class="pdb-sub-item'+(S.pdbSelectedMainCat===mc.id&&S.pdbSelectedSubCat===sc.id?' active':'')+'" onclick="pdbSelectCategory(\''+mc.id+'\',\''+sc.id+'\')">'+sc.name+' ('+sc2+')</div>'}).join('')+'</div>'});tree+='</div>';
  var content='<div style="display:flex;flex-direction:column;gap:10px"><div class="pdb-toolbar"><input id="pdbSearch" placeholder="搜索产品..." oninput="renderProductGrid()" style="width:180px"><select id="pdbMainFilter" onchange="pdbMainFilterChange()"><option value="">全部分类</option>'+PRODUCT_MAIN_CATEGORIES.map(function(mc){return'<option value="'+mc.id+'"'+(S.pdbSelectedMainCat===mc.id?' selected':'')+'>'+mc.icon+' '+mc.name+'</option>'}).join('')+'</select><select id="pdbSubFilter" onchange="pdbSubFilterChange()"><option value="">全部子类</option>'+(S.pdbSelectedMainCat?PRODUCT_MAIN_CATEGORIES.find(function(c){return c.id===S.pdbSelectedMainCat}).subcategories.map(function(sc){return'<option value="'+sc.id+'"'+(S.pdbSelectedSubCat===sc.id?' selected':'')+'>'+sc.name+'</option>'}).join(''):'')+'</select><button class="btn btn-primary btn-sm" onclick="showProductForm()">+ 添加产品</button></div><div id="pdbGridArea"></div></div>';
  body.innerHTML='<div class="pdb-layout">'+tree+content+'</div>';renderProductGrid()}
function pdbSelectCategory(mc,sc){S.pdbSelectedMainCat=mc;S.pdbSelectedSubCat=sc;renderProductDb()}
function pdbMainFilterChange(){S.pdbSelectedMainCat=document.getElementById('pdbMainFilter').value||null;S.pdbSelectedSubCat=null;renderProductDb()}
function pdbSubFilterChange(){S.pdbSelectedSubCat=document.getElementById('pdbSubFilter').value||null;renderProductGrid()}
function getFilteredProducts(){var p=S.products;var s=((document.getElementById('pdbSearch')||{}).value||'').toLowerCase();if(S.pdbSelectedMainCat)p=p.filter(function(x){return x.mainCategory===S.pdbSelectedMainCat});if(S.pdbSelectedSubCat)p=p.filter(function(x){return x.subCategory===S.pdbSelectedSubCat});if(s)p=p.filter(function(x){return(x.name||'').toLowerCase().includes(s)||(x.brand||'').toLowerCase().includes(s)||(x.model||'').toLowerCase().includes(s)});return p}
function getSubCatLabel(mcId,scId){var mc=PRODUCT_MAIN_CATEGORIES.find(function(c){return c.id===mcId});if(!mc)return scId;var s=mc.subcategories.find(function(c){return c.id===scId});return s?s.name:scId}
function renderProductGrid(){var prods=getFilteredProducts();var el=document.getElementById('pdbGridArea');if(!prods.length){el.innerHTML='<div class="empty-state"><div class="icon">📦</div><p>暂无产品</p></div>';return}el.innerHTML='<div class="pdb-grid">'+prods.map(function(p){return '<div class="pdb-card" onclick="showProductForm(\''+p.id+'\')"><div class="pdb-card-img">'+(p.photo?'<img src="'+p.photo+'">':'<div class="pdb-no-img">📦</div>')+'</div><div class="pdb-card-body"><div class="pdb-card-name">'+esc(p.name)+'</div><div class="pdb-card-brand">'+esc(p.brand)+(p.model?' · '+esc(p.model):'')+'</div><div class="pdb-card-specs">'+esc(p.specifications||'')+'</div><div class="pdb-card-price">¥'+fmt(p.unitPrice)+' <span>/'+esc(p.unit)+'</span></div><div style="margin-top:4px"><button class="btn btn-danger btn-sm" onclick="event.stopPropagation();deleteProduct(\''+p.id+'\')" style="font-size:10px;padding:2px 6px">删除</button></div></div></div>'}).join('')+'</div>'}
function showProductForm(pid){S.editingProductId=pid||null;var p=pid?S.products.find(function(x){return x.id===pid}):null;var catOpts=PRODUCT_MAIN_CATEGORIES.map(function(mc){return'<option value="'+mc.id+'" '+(p&&p.mainCategory===mc.id?'selected':'')+'>'+mc.icon+' '+mc.name+'</option>'}).join('');var selMc=p?p.mainCategory:S.pdbSelectedMainCat;var subOpts='';if(selMc){var mc=PRODUCT_MAIN_CATEGORIES.find(function(c){return c.id===selMc});if(mc)subOpts=mc.subcategories.map(function(sc){return'<option value="'+sc.id+'" '+(p&&p.subCategory===sc.id?'selected':'')+'>'+sc.name+'</option>'}).join('')}
  var unitOpts=['㎡','m','个','套','樘','kg','袋','根','块','组','台','副','片'].map(function(u){return'<option value="'+u+'" '+(p&&p.unit===u?' selected':'')+'>'+u+'</option>'}).join('');var envOpts=['','E0级','E1级','ENF级','CARB P2','无甲醛'].map(function(e){return'<option value="'+e+'" '+(p&&p.environmentalRating===e?'selected':'')+'>'+e+'</option>'}).join('');
  var photoHtml=p&&p.photo?'<div class="pdb-photo-preview"><img src="'+p.photo+'"><button class="photo-remove" onclick="removeProductPhoto()">×</button></div>':'<div class="pdb-photo-upload" onclick="document.getElementById(\'pdbPhotoInput\').click()"><div class="upload-icon">📷</div><div class="upload-text">上传产品照片</div></div>';
  document.getElementById('productDbBody').innerHTML='<div style="max-height:70vh;overflow-y:auto;padding:2px"><div class="pdb-form-grid"><div class="pdb-form-group"><label>产品名称 *</label><input id="pdbName" value="'+esc(p?p.name:'')+'"></div><div class="pdb-form-group"><label>品牌</label><input id="pdbBrand" value="'+esc(p?p.brand:'')+'"></div><div class="pdb-form-group"><label>型号</label><input id="pdbModel" value="'+esc(p?p.model:'')+'"></div><div class="pdb-form-group"><label>主类别 *</label><select id="pdbMainCat" onchange="pdbFormCatChange()">'+catOpts+'</select></div><div class="pdb-form-group"><label>子类别 *</label><select id="pdbSubCat">'+(subOpts||'<option value="">请先选主类别</option>')+'</select></div><div class="pdb-form-group"><label>单位</label><select id="pdbUnit">'+unitOpts+'</select></div><div class="pdb-form-group"><label>规格尺寸</label><input id="pdbSpecs" value="'+esc(p?p.specifications:'')+'" placeholder="800×800mm"></div><div class="pdb-form-group"><label>材质</label><input id="pdbMaterial" value="'+esc(p?p.material:'')+'"></div><div class="pdb-form-group"><label>颜色</label><input id="pdbColor" value="'+esc(p?p.color:'')+'"></div><div class="pdb-form-group"><label>单价</label><input type="number" id="pdbPrice" value="'+(p?p.unitPrice:'')+'" step="0.01"></div><div class="pdb-form-group"><label>产地</label><input id="pdbOrigin" value="'+esc(p?p.origin:'')+'"></div><div class="pdb-form-group"><label>环保等级</label><select id="pdbEnv">'+envOpts+'</select></div><div class="pdb-form-group"><label>质保</label><input id="pdbWarranty" value="'+esc(p?p.warranty:'')+'"></div><div class="pdb-form-group full"><label>施工/安装方式</label><input id="pdbInstall" value="'+esc(p?p.installationMethod:'')+'"></div><div class="pdb-form-group full"><label>产品说明</label><textarea id="pdbDesc">'+esc(p?p.description:'')+'</textarea></div><div class="pdb-form-group full"><label>注意事项</label><textarea id="pdbNotes">'+esc(p?p.notes:'')+'</textarea></div></div><div style="margin-top:10px"><label style="font-size:11px;color:var(--text-light)">产品照片</label><div id="pdbPhotoArea">'+photoHtml+'</div><input type="file" id="pdbPhotoInput" accept="image/*" style="display:none" onchange="handleProductPhoto(event)"></div><div style="margin-top:14px;display:flex;gap:8px;justify-content:flex-end"><button class="btn btn-outline" onclick="openProductDatabase()">返回</button><button class="btn btn-primary" onclick="saveProduct()">保存</button></div></div>'}
function pdbFormCatChange(){var mc=document.getElementById('pdbMainCat').value;var sel=document.getElementById('pdbSubCat');var c=PRODUCT_MAIN_CATEGORIES.find(function(x){return x.id===mc});sel.innerHTML=c?c.subcategories.map(function(s){return'<option value="'+s.id+'">'+s.name+'</option>'}).join(''):'<option value="">-</option>'}
function handleProductPhoto(e){var file=e.target.files[0];if(!file)return;compressImage(file,800,0.7,function(b64){var p=S.editingProductId?S.products.find(function(x){return x.id===S.editingProductId}):null;if(p)p.photo=b64;document.getElementById('pdbPhotoArea').innerHTML='<div class="pdb-photo-preview"><img src="'+b64+'"><button class="photo-remove" onclick="removeProductPhoto()">×</button></div>'})}
function removeProductPhoto(){var p=S.editingProductId?S.products.find(function(x){return x.id===S.editingProductId}):null;if(p)p.photo='';document.getElementById('pdbPhotoArea').innerHTML='<div class="pdb-photo-upload" onclick="document.getElementById(\'pdbPhotoInput\').click()"><div class="upload-icon">📷</div><div class="upload-text">上传照片</div></div>';document.getElementById('pdbPhotoInput').value=''}
function saveProduct(){var n=document.getElementById('pdbName').value.trim();var mc=document.getElementById('pdbMainCat').value;var sc=document.getElementById('pdbSubCat').value;if(!n||!mc||!sc){showToast('请填写必填项');return}var d={id:S.editingProductId||uid(),name:n,brand:document.getElementById('pdbBrand').value.trim(),model:document.getElementById('pdbModel').value.trim(),mainCategory:mc,subCategory:sc,specifications:document.getElementById('pdbSpecs').value.trim(),material:document.getElementById('pdbMaterial').value.trim(),color:document.getElementById('pdbColor').value.trim(),unit:document.getElementById('pdbUnit').value,unitPrice:parseFloat(document.getElementById('pdbPrice').value)||0,origin:document.getElementById('pdbOrigin').value.trim(),environmentalRating:document.getElementById('pdbEnv').value,warranty:document.getElementById('pdbWarranty').value.trim(),installationMethod:document.getElementById('pdbInstall').value.trim(),description:document.getElementById('pdbDesc').value.trim(),notes:document.getElementById('pdbNotes').value.trim(),photo:'',createdAt:Date.now(),updatedAt:Date.now()};if(S.editingProductId){var idx=S.products.findIndex(function(x){return x.id===S.editingProductId});if(idx>=0){d.photo=S.products[idx].photo;d.createdAt=S.products[idx].createdAt;S.products[idx]=d}}else S.products.push(d);saveProductsToStorage();showToast('已保存');showProductForm(null);renderProductDb()}
function deleteProduct(id){if(!confirm('确定删除？'))return;S.products=S.products.filter(function(p){return p.id!==id});saveProductsToStorage();renderProductGrid()}

// ==================== ADD PRODUCTS TO QUOTE ====================
function openAddProductsToQuote(){if(!S.currentFileId){showToast('请先打开报价文件');return}S.addProdSelectedIds=[];renderApqList();openModal('addProdToQuoteModal')}
function renderApqList(){var body=document.getElementById('addProdToQuoteBody');body.innerHTML='<div class="lib-filter"><select id="apqMainFilter" onchange="apqFilterChange()"><option value="">全部分类</option>'+PRODUCT_MAIN_CATEGORIES.map(function(mc){return'<option value="'+mc.id+'">'+mc.icon+' '+mc.name+'</option>'}).join('')+'</select><select id="apqSubFilter" onchange="renderApqList()"><option value="">全部子类</option></select><input id="apqSearch" placeholder="搜索..." oninput="renderApqList()" style="width:150px"></div><div id="apqListArea" style="max-height:380px;overflow-y:auto"></div>';document.getElementById('apqMainFilter').onchange=apqFilterChange;renderApqListInner()}
function apqFilterChange(){var mc=PRODUCT_MAIN_CATEGORIES.find(function(c){return c.id===document.getElementById('apqMainFilter').value});document.getElementById('apqSubFilter').innerHTML=mc?'<option value="">全部子类</option>'+mc.subcategories.map(function(s){return'<option value="'+s.id+'">'+s.name+'</option>'}).join(''):'<option value="">全部子类</option>';renderApqListInner()}
function renderApqListInner(){var mf=document.getElementById('apqMainFilter').value;var sf=document.getElementById('apqSubFilter').value;var sr=(document.getElementById('apqSearch').value||'').toLowerCase();var prods=S.products;if(mf)prods=prods.filter(function(p){return p.mainCategory===mf});if(sf)prods=prods.filter(function(p){return p.subCategory===sf});if(sr)prods=prods.filter(function(p){return(p.name||'').toLowerCase().includes(sr)||(p.brand||'').toLowerCase().includes(sr)});var el=document.getElementById('apqListArea');if(!prods.length){el.innerHTML='<div class="empty-state"><p>暂无</p></div>';return}el.innerHTML='<div class="pdb-select-list">'+prods.map(function(p){var sel=S.addProdSelectedIds.indexOf(p.id)>=0;var th=p.photo?'<img src="'+p.photo+'">':'<div class="no-img">📦</div>';return '<div class="pdb-select-item'+(sel?' selected':'')+'" onclick="toggleApqSelect(\''+p.id+'\')"><div class="psi-thumb">'+th+'</div><div class="psi-info"><div class="psi-name">'+esc(p.name)+(p.brand?' · '+esc(p.brand):'')+'</div><div class="psi-detail">'+esc(p.specifications||'')+'</div></div><div class="psi-price">¥'+fmt(p.unitPrice)+'/'+esc(p.unit)+'</div><input class="psi-qty" type="number" value="1" min="0" onclick="event.stopPropagation()"></div>'}).join('')+'</div>'}
var apqQt={};function toggleApqSelect(id){var i=S.addProdSelectedIds.indexOf(id);if(i>=0)S.addProdSelectedIds.splice(i,1);else S.addProdSelectedIds.push(id);renderApqListInner()}
function confirmAddProductsToQuote(){if(!S.addProdSelectedIds.length){showToast('请选择产品');return}S.addProdSelectedIds.forEach(function(id){var p=S.products.find(function(x){return x.id===id});if(!p)return;var qEl=document.querySelector('.psi-qty[onclick*="'+id+'"]');var qty=qEl?parseFloat(qEl.value)||1:1;var ex=S.productQuoteItems.find(function(q){return q.productId===id});if(ex)ex.quantity+=qty;else S.productQuoteItems.push({id:uid(),productId:p.id,name:p.name,brand:p.brand,model:p.model,mainCategory:p.mainCategory,subCategory:p.subCategory,specifications:p.specifications,material:p.material,color:p.color,quantity:qty,unit:p.unit,unitPrice:p.unitPrice,description:p.description||'',notes:p.notes||'',photo:p.photo||''})});S.addProdSelectedIds=[];closeModal('addProdToQuoteModal');renderQuoteTable();renderSummary();showToast('已添加');markDirty()}

// ==================== EXPORT VERSIONS ====================
function toggleExportMenu(e){e.stopPropagation();document.getElementById('exportMenu').classList.toggle('show');document.getElementById('printMenu').classList.remove('show')}
function togglePrintMenu(e){e.stopPropagation();document.getElementById('printMenu').classList.toggle('show');document.getElementById('exportMenu').classList.remove('show')}
document.addEventListener('click',closeAllMenus);

function calcQuoteTotal(){var engTotal=S.quoteItems.reduce(function(s,i){return s+(i.quantity||0)*(i.unitPrice||0)},0);var prodTotal=S.productQuoteItems.reduce(function(s,i){return s+(i.quantity||0)*(i.unitPrice||0)},0);var sub=engTotal+prodTotal;var mgmt=sub*S.managementFeeRate/100;var tax=sub*S.taxRate/100;return{engTotal:engTotal,prodTotal:prodTotal,subtotal:sub,mgmt:mgmt,tax:tax,grandTotal:sub+mgmt+tax+S.garbageFee+S.protectionFee}}
function exportPDF(version){if(!S.currentFileId){showToast('请先打开报价文件');return}var ci=S.customerInfo;var labels={luxury:'奢享全案',premium:'优享精造'};var totals=calcQuoteTotal();var el=document.createElement('div');el.style.cssText='padding:20px 24px;font-family:"Microsoft YaHei",sans-serif;color:#222;background:#fff;width:780px;margin:0 auto';
  if(version==='simple'){el.innerHTML=simpleExportHTML(ci,labels,totals)}else{el.innerHTML=detailedExportHTML(ci,labels,totals)}
  document.body.appendChild(el);html2pdf().set({margin:10,filename:'报价单-'+(version==='simple'?'简约':'详细')+'版.pdf',image:{type:'jpeg',quality:0.98},html2canvas:{scale:2,useCORS:true},jsPDF:{unit:'mm',format:'a4',orientation:'portrait'}}).from(el).save().then(function(){document.body.removeChild(el)}).catch(function(){document.body.removeChild(el)})}
function printQuote(version){if(!S.currentFileId){showToast('请先打开报价文件');return}var ci=S.customerInfo;var labels={luxury:'奢享全案',premium:'优享精造'};var totals=calcQuoteTotal();var html;if(version==='simple')html=simpleExportHTML(ci,labels,totals);else html=detailedExportHTML(ci,labels,totals);html='<div style="position:fixed;top:0;right:10px"><button onclick="window.print()" style="padding:8px 16px;border:1px solid #ccc;background:#fff;cursor:pointer;border-radius:6px;font-size:14px">打印</button></div>'+html;var w=window.open('','_blank');w.document.write('<!DOCTYPE html><html><head><meta charset="UTF-8"><title>报价单</title><style>*{margin:0;padding:0;box-sizing:border-box}body{font-family:"Microsoft YaHei",sans-serif;padding:20px;color:#222}</style></head><body>'+html);w.document.close()}
function exportHeaderHTML(ci,labels){var logoSrc=typeof LOGO_BASE64==='string'?LOGO_BASE64:'';return '<div style="text-align:center;margin-bottom:16px">'+(logoSrc?'<img src="'+logoSrc+'" style="width:40px;height:40px;object-fit:contain;margin-bottom:4px">':'')+'<div style="font-size:22px;font-weight:700;letter-spacing:2px">斑马精装报价单</div><div style="font-size:12px;color:#888;margin-top:2px">'+(labels[S.currentPlan]||'')+'</div></div><table style="width:100%;font-size:12px;border-collapse:collapse;margin-bottom:12px"><tr><td style="width:25%;padding:4px 0;border-bottom:1px solid #e0e0e0"><b>客户：</b>'+esc(ci.name)+'</td><td style="width:25%;padding:4px 0;border-bottom:1px solid #e0e0e0"><b>联系方式：</b>'+esc(ci.phone)+'</td><td style="width:25%;padding:4px 0;border-bottom:1px solid #e0e0e0"><b>设计师：</b>'+esc(ci.designer)+'</td><td style="width:25%;padding:4px 0;border-bottom:1px solid #e0e0e0"><b>设计师电话：</b>'+esc(ci.designerPhone)+'</td></tr><tr><td colspan="2" style="padding:4px 0;border-bottom:1px solid #e0e0e0"><b>地址：</b>'+esc(ci.address)+'</td><td style="padding:4px 0;border-bottom:1px solid #e0e0e0"><b>工艺标准：</b>'+(labels[S.currentPlan]||'')+'</td><td style="padding:4px 0;border-bottom:1px solid #e0e0e0"><b>日期：</b>'+esc(ci.date)+'</td></tr><tr><td colspan="4" style="padding:4px 0"><b>面积：</b>'+esc(ci.area)+'㎡</td></tr></table>'}
function exportSummaryHTML(totals){return '<div style="margin-top:14px"><table style="width:100%;border-collapse:collapse;font-size:12px"><tr style="border-bottom:1px solid #e0e0e0"><td style="padding:6px 0">工程报价</td><td style="padding:6px 0;text-align:center;font-weight:600;white-space:nowrap">¥'+fmt(totals.engTotal)+'</td></tr>'+(totals.prodTotal>0?'<tr style="border-bottom:1px solid #e0e0e0"><td style="padding:6px 0">产品清单</td><td style="padding:6px 0;text-align:center;font-weight:600;white-space:nowrap">¥'+fmt(totals.prodTotal)+'</td></tr>':'')+'<tr style="border-bottom:1px solid #e0e0e0"><td style="padding:6px 0">直接费用</td><td style="padding:6px 0;text-align:center;font-weight:600;white-space:nowrap">¥'+fmt(totals.subtotal)+'</td></tr><tr style="border-bottom:1px solid #e0e0e0"><td style="padding:6px 0">管理费 ('+S.managementFeeRate+'%)</td><td style="padding:6px 0;text-align:center;white-space:nowrap">¥'+fmt(totals.mgmt)+'</td></tr><tr style="border-bottom:1px solid #e0e0e0"><td style="padding:6px 0">税金 ('+S.taxRate+'%)</td><td style="padding:6px 0;text-align:center;white-space:nowrap">¥'+fmt(totals.tax)+'</td></tr><tr style="border-bottom:1px solid #e0e0e0"><td style="padding:6px 0">垃圾清运</td><td style="padding:6px 0;text-align:center;white-space:nowrap">¥'+fmt(S.garbageFee)+'</td></tr><tr style="border-bottom:1px solid #e0e0e0"><td style="padding:6px 0">成品保护</td><td style="padding:6px 0;text-align:center;white-space:nowrap">¥'+fmt(S.protectionFee)+'</td></tr><tr><td style="padding:8px 0;font-size:14px;font-weight:700;border-top:2px solid #333">报价总计</td><td style="padding:8px 0;text-align:center;font-size:16px;font-weight:700;color:#c00;border-top:2px solid #333;white-space:nowrap">¥'+fmt(totals.grandTotal)+'</td></tr></table></div>'}
function simpleExportHTML(ci,labels,totals){return exportHeaderHTML(ci,labels)+(S.customNotes?'<div style="margin-bottom:12px"><div style="font-size:12px;font-weight:600;margin-bottom:4px">备注信息</div><div style="font-size:11px;white-space:pre-wrap;line-height:1.8;color:#555">'+esc(S.customNotes)+'</div></div>':'')+exportSimpleTable()+exportSummaryHTML(totals)}
function detailedExportHTML(ci,labels,totals){return exportHeaderHTML(ci,labels)+exportDetailedTable()+exportSummaryHTML(totals)}
function exportSimpleTable(){var items=S.quoteItems.concat(S.productQuoteItems);var seq=1;var sg={};S.rooms.forEach(function(r){if(!sg[r.spaceTypeId])sg[r.spaceTypeId]=[];sg[r.spaceTypeId].push(r)});var h='<table style="width:100%;border-collapse:collapse;font-size:11px;margin-top:10px;table-layout:auto"><thead><tr style="border-bottom:2px solid #bbb"><th style="padding:6px 4px;text-align:center;width:32px">序号</th><th style="padding:6px 4px;text-align:center">项目</th><th style="padding:6px 4px;text-align:center;white-space:nowrap;min-width:80px">金额</th></tr></thead><tbody>';Object.keys(sg).forEach(function(stId){var st=S.spaceTypes.find(function(s){return s.id===stId});var rooms=sg[stId];var si=items.filter(function(q){return rooms.some(function(r){return r.id===q.roomId})});if(!si.length)return;var stT=si.reduce(function(s,q){return s+q.quantity*q.unitPrice},0);h+='<tr><td colspan="3" style="padding:7px 4px;font-weight:600;font-size:12px;border-bottom:1px solid #e0e0e0">'+(st?st.icon:'')+' '+(st?st.name:'')+'<span style="float:right;white-space:nowrap">¥'+fmt(stT)+'</span></td></tr>';rooms.forEach(function(room){var ri=si.filter(function(q){return q.roomId===room.id});if(!ri.length)return;var rT=ri.reduce(function(s,q){return s+q.quantity*q.unitPrice},0);h+='<tr><td colspan="3" style="padding:5px 4px 5px 16px;font-weight:600;border-bottom:1px solid #f0f0f0">📍 '+esc(room.name)+'<span style="float:right;white-space:nowrap">¥'+fmt(rT)+'</span></td></tr>';ri.forEach(function(qi){h+='<tr style="border-bottom:1px solid #f0f0f0"><td style="padding:4px;text-align:center">'+seq+'</td><td style="padding:4px">'+esc(qi.name)+'</td><td style="padding:4px;text-align:center;font-weight:500;white-space:nowrap">¥'+fmt(qi.quantity*qi.unitPrice)+'</td></tr>';seq++})})});var ui=items.filter(function(q){return q.roomId==='__utility__'});if(ui.length){var uT=ui.reduce(function(s,q){return s+q.quantity*q.unitPrice},0);h+='<tr><td colspan="3" style="padding:7px 4px;font-weight:600;font-size:12px;border-bottom:1px solid #e0e0e0">⚡ 水电暖气下水<span style="float:right;white-space:nowrap">¥'+fmt(uT)+'</span></td></tr>';ui.forEach(function(q){h+='<tr style="border-bottom:1px solid #f0f0f0"><td style="padding:4px;text-align:center">'+seq+'</td><td style="padding:4px">'+esc(q.name)+'</td><td style="padding:4px;text-align:center;font-weight:500;white-space:nowrap">¥'+fmt(q.quantity*q.unitPrice)+'</td></tr>';seq++})}var citems=items.filter(function(q){return q.roomId==='__custom__'});if(citems.length){h+='<tr><td colspan="3" style="padding:7px 4px;font-weight:600;font-size:12px;border-bottom:1px solid #e0e0e0">📝 自定义</td></tr>';citems.forEach(function(q){h+='<tr style="border-bottom:1px solid #f0f0f0"><td style="padding:4px;text-align:center">'+seq+'</td><td style="padding:4px">'+esc(q.name)+'</td><td style="padding:4px;text-align:center;font-weight:500;white-space:nowrap">¥'+fmt(q.quantity*q.unitPrice)+'</td></tr>';seq++})}if(S.productQuoteItems.length){PRODUCT_MAIN_CATEGORIES.forEach(function(mc){var pi=S.productQuoteItems.filter(function(q){return q.mainCategory===mc.id});if(!pi.length)return;var pT=pi.reduce(function(s,q){return s+q.quantity*q.unitPrice},0);h+='<tr><td colspan="3" style="padding:7px 4px;font-weight:600;font-size:12px;border-bottom:1px solid #e0e0e0">'+mc.icon+' '+mc.name+'<span style="float:right;white-space:nowrap">¥'+fmt(pT)+'</span></td></tr>';pi.forEach(function(q){h+='<tr style="border-bottom:1px solid #f0f0f0"><td style="padding:4px;text-align:center">'+seq+'</td><td style="padding:4px">'+esc(q.name)+'</td><td style="padding:4px;text-align:center;font-weight:500;white-space:nowrap">¥'+fmt(q.quantity*q.unitPrice)+'</td></tr>';seq++})})}h+='</tbody></table>';return h}
function exportDetailedTable(){var items=S.quoteItems.concat(S.productQuoteItems);var seq=1;var sg={};S.rooms.forEach(function(r){if(!sg[r.spaceTypeId])sg[r.spaceTypeId]=[];sg[r.spaceTypeId].push(r)});var h='<table style="width:100%;border-collapse:collapse;font-size:10px;margin-top:10px;table-layout:auto"><thead><tr style="border-bottom:2px solid #bbb"><th style="padding:5px 3px;text-align:center;width:28px">序号</th><th style="padding:5px 3px;text-align:center">项目</th><th style="padding:5px 3px;text-align:center;width:38px">数量</th><th style="padding:5px 3px;text-align:center;width:32px">单位</th><th style="padding:5px 3px;text-align:center;white-space:nowrap;min-width:55px">单价</th><th style="padding:5px 3px;text-align:center;white-space:nowrap;min-width:65px">金额</th><th style="padding:5px 3px;text-align:center">说明</th></tr></thead><tbody>';function dRow(qi,s){return '<tr style="border-bottom:1px solid #f0f0f0"><td style="padding:3px 2px;text-align:center">'+s+'</td><td style="padding:3px 2px;white-space:nowrap">'+esc(qi.name)+'</td><td style="padding:3px 2px;text-align:center">'+qi.quantity+'</td><td style="padding:3px 2px;text-align:center">'+esc(qi.unit)+'</td><td style="padding:3px 2px;text-align:center;white-space:nowrap">¥'+fmt(qi.unitPrice)+'</td><td style="padding:3px 2px;text-align:center;font-weight:600;white-space:nowrap">¥'+fmt(qi.quantity*qi.unitPrice)+'</td><td style="padding:3px 2px;color:#666;font-size:9px;font-family:\'Microsoft YaHei UI Light\',\'Microsoft YaHei Light\',sans-serif;font-weight:300">'+esc(qi.description||'')+'</td></tr>'}Object.keys(sg).forEach(function(stId){var st=S.spaceTypes.find(function(s){return s.id===stId});var rooms=sg[stId];var si=items.filter(function(q){return rooms.some(function(r){return r.id===q.roomId})});if(!si.length)return;var stT=si.reduce(function(s,q){return s+q.quantity*q.unitPrice},0);h+='<tr><td colspan="7" style="padding:6px 3px;font-weight:600;font-size:11px;border-bottom:1px solid #e0e0e0">'+(st?st.icon:'')+' '+(st?st.name:'')+'<span style="float:right;white-space:nowrap">¥'+fmt(stT)+'</span></td></tr>';rooms.forEach(function(room){var ri=si.filter(function(q){return q.roomId===room.id});if(!ri.length)return;var rT=ri.reduce(function(s,q){return s+q.quantity*q.unitPrice},0);h+='<tr><td colspan="7" style="padding:4px 3px 4px 14px;font-weight:600;border-bottom:1px solid #f0f0f0">📍 '+esc(room.name)+'<span style="float:right;white-space:nowrap">¥'+fmt(rT)+'</span></td></tr>';ri.forEach(function(qi){h+=dRow(qi,seq++)})})});var ui=items.filter(function(q){return q.roomId==='__utility__'});if(ui.length){var uT=ui.reduce(function(s,q){return s+q.quantity*q.unitPrice},0);h+='<tr><td colspan="7" style="padding:6px 3px;font-weight:600;font-size:11px;border-bottom:1px solid #e0e0e0">⚡ 水电暖气下水<span style="float:right;white-space:nowrap">¥'+fmt(uT)+'</span></td></tr>';ui.forEach(function(q){h+=dRow(q,seq++)})}var citems=items.filter(function(q){return q.roomId==='__custom__'});if(citems.length){h+='<tr><td colspan="7" style="padding:6px 3px;font-weight:600;font-size:11px;border-bottom:1px solid #e0e0e0">📝 自定义</td></tr>';citems.forEach(function(q){h+=dRow(q,seq++)})}if(S.productQuoteItems.length){PRODUCT_MAIN_CATEGORIES.forEach(function(mc){var pi=S.productQuoteItems.filter(function(q){return q.mainCategory===mc.id});if(!pi.length)return;var pT=pi.reduce(function(s,q){return s+q.quantity*q.unitPrice},0);h+='<tr><td colspan="7" style="padding:6px 3px;font-weight:600;font-size:11px;border-bottom:1px solid #e0e0e0">'+mc.icon+' '+mc.name+'<span style="float:right;white-space:nowrap">¥'+fmt(pT)+'</span></td></tr>';pi.forEach(function(q){h+=dRow(q,seq++)})})}h+='</tbody></table>';return h}
function cleanTableHTML(){return document.getElementById('quoteTableWrapper').innerHTML.replace(/class="qt-input"[^>]*>/g,'style="border:none;background:transparent;font-size:11px"').replace(/class="btn-x[^"]*"/g,'style="display:none"').replace(/class="[^"]*no-print[^"]*"/g,'style="display:none"').replace(/onchange="[^"]*"/g,'').replace(/onclick="[^"]*"/g,'')}

// ==================== EXPORT EXCEL ====================
function exportExcel(){if(!S.currentFileId){showToast('请先打开报价文件');return}if(typeof XLSX==='undefined'){showToast('Excel组件加载中，请稍后重试');return}
var ci=S.customerInfo;var labels={luxury:'奢享全案',premium:'优享精造'};var totals=calcQuoteTotal();
var rows=[];var merges=[];var R=0;
// Title row
rows.push(['斑马精装报价单','','','','','','']);merges.push({s:{r:R,c:0},e:{r:R,c:6}});R++;
// Plan label
rows.push([labels[S.currentPlan]||'','','','','','','']);merges.push({s:{r:R,c:0},e:{r:R,c:6}});R++;
// Empty
rows.push(['','','','','','','']);R++;
// Customer info
rows.push(['客户：'+(ci.name||''),'联系方式：'+(ci.phone||''),'设计师：'+(ci.designer||''),'设计师电话：'+(ci.designerPhone||''),'','','']);R++;
rows.push(['地址：'+(ci.address||''),'','工艺标准：'+(labels[S.currentPlan]||''),'日期：'+(ci.date||''),'','','']);merges.push({s:{r:R-1,c:0},e:{r:R-1,c:1}});R++;
rows.push(['面积：'+(ci.area||'')+'㎡','','','','','','']);merges.push({s:{r:R-1,c:0},e:{r:R-1,c:1}});R++;
// Empty
rows.push(['','','','','','','']);R++;
// Table header
rows.push(['序号','项目','数量','单位','单价','金额','说明']);R++;
// Build quote data
var seq=1;var sg={};
S.rooms.forEach(function(r){if(!sg[r.spaceTypeId])sg[r.spaceTypeId]=[];sg[r.spaceTypeId].push(r)});
var catOrd=['拆除工程','砌筑工程','水电工程','防水工程','泥瓦工程','木作工程','油漆工程','墙面工程','地面工程','顶面工程','门窗工程','暖气改造','下水改造','安装工程','楼梯工程','设备产品','定制产品','背景墙'];
Object.keys(sg).forEach(function(stId){var st=S.spaceTypes.find(function(s){return s.id===stId});var rooms=sg[stId];var si=S.quoteItems.filter(function(q){return rooms.some(function(r){return r.id===q.roomId})});if(!si.length)return;var stT=si.reduce(function(s,q){return s+q.quantity*q.unitPrice},0);
rows.push([(st?st.name:'')+'  ¥'+fmt(stT),'','','','','','']);merges.push({s:{r:R,c:0},e:{r:R,c:6}});R++;
rooms.forEach(function(room){var ri=si.filter(function(q){return q.roomId===room.id});if(!ri.length)return;var rT=ri.reduce(function(s,q){return s+q.quantity*q.unitPrice},0);
rows.push([room.name+'  ¥'+fmt(rT),'','','','','','']);merges.push({s:{r:R,c:0},e:{r:R,c:6}});R++;
catOrd.forEach(function(cat){var cItems=ri.filter(function(q){return q.category===cat});if(!cItems.length)return;
rows.push(['','▸ '+cat,'','','¥'+fmt(cItems.reduce(function(s,q){return s+q.quantity*q.unitPrice},0)),'','']);R++;
cItems.forEach(function(qi){rows.push([seq,qi.name,qi.quantity,qi.unit,qi.unitPrice,qi.quantity*qi.unitPrice,qi.description||'']);seq++;R++})})})});
// Utility items
var ui=S.quoteItems.filter(function(q){return q.roomId==='__utility__'});if(ui.length){var uT=ui.reduce(function(s,q){return s+q.quantity*q.unitPrice},0);
rows.push(['水电暖气下水  ¥'+fmt(uT),'','','','','','']);merges.push({s:{r:R,c:0},e:{r:R,c:6}});R++;
ui.forEach(function(q){rows.push([seq,q.name,q.quantity,q.unit,q.unitPrice,q.quantity*q.unitPrice,q.description||'']);seq++;R++})}
// Custom items
var citems=S.quoteItems.filter(function(q){return q.roomId==='__custom__'});if(citems.length){
rows.push(['自定义','','','','','','']);merges.push({s:{r:R,c:0},e:{r:R,c:6}});R++;
citems.forEach(function(q){rows.push([seq,q.name,q.quantity,q.unit,q.unitPrice,q.quantity*q.unitPrice,q.description||'']);seq++;R++})}
// Product items
if(S.productQuoteItems.length){PRODUCT_MAIN_CATEGORIES.forEach(function(mc){var pi=S.productQuoteItems.filter(function(q){return q.mainCategory===mc.id});if(!pi.length)return;var pT=pi.reduce(function(s,q){return s+q.quantity*q.unitPrice},0);
rows.push([mc.name+'  ¥'+fmt(pT),'','','','','','']);merges.push({s:{r:R,c:0},e:{r:R,c:6}});R++;
var subG={};pi.forEach(function(q){if(!subG[q.subCategory])subG[q.subCategory]=[];subG[q.subCategory].push(q)});
Object.keys(subG).forEach(function(subId){var subI=subG[subId];var sT=subI.reduce(function(s,q){return s+q.quantity*q.unitPrice},0);
rows.push(['','▸ '+getSubCatLabel(mc.id,subId),'','','¥'+fmt(sT),'','']);R++;
subI.forEach(function(q){rows.push([seq,q.name,q.quantity,q.unit,q.unitPrice,q.quantity*q.unitPrice,q.description||'']);seq++;R++})})})}
// Empty row before summary
rows.push(['','','','','','','']);R++;
// Summary section
rows.push(['工程报价','','','','',totals.engTotal,'']);R++;
if(totals.prodTotal>0){rows.push(['产品清单','','','','',totals.prodTotal,'']);R++}
rows.push(['直接费用合计','','','','',totals.subtotal,'']);R++;
rows.push(['管理费 ('+S.managementFeeRate+'%)','','','','',totals.mgmt,'']);R++;
rows.push(['税金 ('+S.taxRate+'%)','','','','',totals.tax,'']);R++;
rows.push(['垃圾清运','','','','',S.garbageFee,'']);R++;
rows.push(['成品保护','','','','',S.protectionFee,'']);R++;
rows.push(['报价总计','','','','',totals.grandTotal,'']);R++;
// Create workbook
var ws=XLSX.utils.aoa_to_sheet(rows);
ws['!merges']=merges;
ws['!cols']=[{wch:6},{wch:24},{wch:8},{wch:6},{wch:10},{wch:12},{wch:40}];
// Style header row and group rows
var wb=XLSX.utils.book_new();XLSX.utils.book_append_sheet(wb,ws,'报价单');
XLSX.writeFile(wb,'报价单-'+(ci.address||'详细')+'版.xlsx');
showToast('已导出Excel')}

// ==================== MEASUREMENT EDITOR ====================
function renderMeasurementView(){document.getElementById('msProjectName').value=S.msProjectName;renderMsRoomList()}
function onMsProjectNameChange(){S.msProjectName=document.getElementById('msProjectName').value;markDirty()}
function renderMsRoomList(){var el=document.getElementById('msRoomList');if(!S.msRooms.length){el.innerHTML='<div class="empty-state"><div class="icon">📐</div><p>点击上方按钮添加房间</p></div>';return}el.innerHTML=S.msRooms.map(function(r){var st=S.spaceTypes.find(function(s){return s.id===r.spaceTypeId});var wa=Math.max(0,r.perimeter*r.height-(r.doors||[]).reduce(function(s,d){return s+d.width*d.height},0)-(r.windows||[]).reduce(function(s,w){return s+w.width*w.height},0));var sk=Math.max(0,r.perimeter-(r.doors||[]).reduce(function(s,d){return s+d.width},0));return '<div class="ms-room-item"><div class="ms-room-header"><span class="ms-room-name">'+(st?st.icon:'')+' '+esc(r.name)+'</span><span class="ms-room-type">'+(st?st.name:'')+'</span></div><div class="ms-room-dims">面积: '+r.area+'㎡ | 周长: '+r.perimeter+'m | 高: '+r.height+'m</div><div class="ms-room-detail"><div class="ms-detail-tag">地面 <span>'+r.area+'</span> ㎡</div><div class="ms-detail-tag">墙面 <span>'+fmt(wa)+'</span> ㎡</div><div class="ms-detail-tag">踢脚线 <span>'+fmt(sk)+'</span> m</div></div><div class="ms-room-actions"><button class="btn btn-outline btn-sm" onclick="editMsRoom(\''+r.id+'\')">编辑</button><button class="btn btn-danger btn-sm" onclick="deleteMsRoom(\''+r.id+'\')">删除</button></div></div>'}).join('')}
function openMsRoomEditor(rid){S.msEditingRoomId=rid||null;var r=rid?S.msRooms.find(function(x){return x.id===rid}):null;document.getElementById('msRoomEditorTitle').textContent=r?'编辑房间':'添加房间';var stO=S.spaceTypes.map(function(s){return'<option value="'+s.id+'" '+(r&&r.spaceTypeId===s.id?'selected':'')+'>'+s.icon+' '+s.name+'</option>'}).join('');var cO=['衣柜','电视柜','书柜','橱柜','护墙板','门','踢脚线'].map(function(n){return'<option value="'+n+'">'+n+'</option>'}).join('');document.getElementById('msRoomEditorBody').innerHTML='<div class="form-grid"><div class="form-group"><label>房间名称</label><input id="mreName" value="'+(r?esc(r.name):'')+'"></div><div class="form-group"><label>空间类型</label><select id="mreSpaceType">'+stO+'</select></div><div class="form-group"><label>面积 (㎡)</label><input type="number" id="mreArea" value="'+(r?r.area:'')+'" step="0.01"></div><div class="form-group"><label>周长 (m)</label><input type="number" id="mrePerimeter" value="'+(r?r.perimeter:'')+'" step="0.01"></div><div class="form-group"><label>高度 (m)</label><input type="number" id="mreHeight" value="'+(r?r.height:'')+'" step="0.01"></div></div><div class="sub-section"><h4>门</h4><div id="mreDoors">'+(r?(r.doors||[]).map(dwRow).join(''):'')+'</div><button class="btn btn-outline btn-sm" onclick="addMsDoor()">+ 添加</button></div><div class="sub-section"><h4>窗户</h4><div id="mreWindows">'+(r?(r.windows||[]).map(dwRow).join(''):'')+'</div><button class="btn btn-outline btn-sm" onclick="addMsWindow()">+ 添加</button></div><div class="sub-section"><h4>定制</h4><div style="margin-bottom:6px"><select id="msCPS"><option value="">选择预设...</option>'+cO+'</select> <button class="btn btn-outline btn-sm" onclick="addMsPresetCustom()">添加</button></div><div id="mreCustomItems">'+(r?(r.customItems||[]).map(msCR).join(''):'')+'</div><button class="btn btn-outline btn-sm" onclick="addMsCustomItem()">+ 自定义</button></div>';openModal('msRoomEditorModal')}
function editMsRoom(id){openMsRoomEditor(id)}function addMsDoor(){var c=document.getElementById('mreDoors');var d=document.createElement('div');d.innerHTML=dwRow({});c.appendChild(d.firstElementChild)}function addMsWindow(){var c=document.getElementById('mreWindows');var d=document.createElement('div');d.innerHTML=dwRow({});c.appendChild(d.firstElementChild)}function msCR(d){return'<div class="custom-row"><input placeholder="名称" value="'+(d?esc(d.name):'')+'" style="width:90px"><input placeholder="长" value="'+(d?d.length:'')+'" type="number" step="0.01" style="width:60px"><input placeholder="深" value="'+(d?d.depth:'')+'" type="number" step="0.01" style="width:60px"><input placeholder="高" value="'+(d?d.height:'')+'" type="number" step="0.01" style="width:60px"><button class="btn-x" onclick="this.parentElement.remove()">×</button></div>'}
function addMsCustomItem(){var c=document.getElementById('mreCustomItems');var d=document.createElement('div');d.innerHTML=msCR({});c.appendChild(d.firstElementChild)}function addMsPresetCustom(){var s=document.getElementById('msCPS');if(!s.value)return;var c=document.getElementById('mreCustomItems');var d=document.createElement('div');d.innerHTML=msCR({name:s.value,length:'',depth:0.6,height:''});c.appendChild(d.firstElementChild);s.value=''}
function saveMsRoom(){var name=document.getElementById('mreName').value.trim();var stId=document.getElementById('mreSpaceType').value;var area=parseFloat(document.getElementById('mreArea').value)||0;var peri=parseFloat(document.getElementById('mrePerimeter').value)||0;var h=parseFloat(document.getElementById('mreHeight').value)||0;if(!area||!peri||!h){showToast('请输入面积、周长和高度');return}var doors=[],windows=[],customs=[];document.querySelectorAll('#mreDoors .door-win-row').forEach(function(row){var i=row.querySelectorAll('input');var w=parseFloat(i[0].value)||0,h=parseFloat(i[1].value)||0;if(w&&h)doors.push({width:w,height:h})});document.querySelectorAll('#mreWindows .door-win-row').forEach(function(row){var i=row.querySelectorAll('input');var w=parseFloat(i[0].value)||0,h=parseFloat(i[1].value)||0;if(w&&h)windows.push({width:w,height:h})});document.querySelectorAll('#mreCustomItems .custom-row').forEach(function(row){var i=row.querySelectorAll('input');var n=i[0].value.trim(),l=parseFloat(i[1].value)||0,d=parseFloat(i[2].value)||0,h=parseFloat(i[3].value)||0;if(n&&l&&h)customs.push({name:n,length:l,depth:d,height:h})});var st=S.spaceTypes.find(function(s){return s.id===stId});var rd={id:S.msEditingRoomId||uid(),name:name||(st?st.name:'房间'),spaceTypeId:stId,area:area,perimeter:peri,height:h,doors:doors,windows:windows,customItems:customs};if(S.msEditingRoomId){var idx=S.msRooms.findIndex(function(x){return x.id===S.msEditingRoomId});if(idx>=0)S.msRooms[idx]=rd}else S.msRooms.push(rd);closeModal('msRoomEditorModal');renderMsRoomList();showToast('已保存');markDirty()}
function deleteMsRoom(id){if(!confirm('确定删除？'))return;S.msRooms=S.msRooms.filter(function(r){return r.id!==id});renderMsRoomList();markDirty()}

// ==================== IMPORT ====================
function openImportDialog(){if(!S.currentFileId){showToast('请先打开报价');return}var cf=S.files.find(function(f){return f.id===S.currentFileId});if(!cf||cf.type!=='quotation'){showToast('请先打开报价');return}S.importSelectedFileId=null;var ms=S.files.filter(function(f){return f.type==='measurement'});if(!ms.length){showToast('暂无量房文件');return}document.getElementById('importDialogBody').innerHTML='<p style="margin-bottom:10px;font-size:12px;color:var(--text-light)">选择量房文件：</p><div class="import-file-list">'+ms.map(function(f){return '<div class="import-file-item" data-id="'+f.id+'" onclick="selectImportFile(\''+f.id+'\')"><span class="ifi-icon">📐</span><div class="ifi-info"><div class="ifi-name">'+esc(f.name)+'</div><div class="ifi-detail">'+(f.data.rooms||[]).length+' 房间 · '+formatDate(f.updatedAt)+'</div></div></div>'}).join('')+'</div>';document.getElementById('importNextBtn').disabled=true;openModal('importDialogModal')}
function selectImportFile(id){S.importSelectedFileId=id;document.querySelectorAll('.import-file-item').forEach(function(e){e.classList.remove('selected')});document.querySelector('.import-file-item[data-id="'+id+'"]').classList.add('selected');document.getElementById('importNextBtn').disabled=false}
function showImportConfirmation(){if(!S.importSelectedFileId)return;var file=S.files.find(function(f){return f.id===S.importSelectedFileId});if(!file)return;var rooms=file.data.rooms||[];closeModal('importDialogModal');document.getElementById('importConfirmBody').innerHTML='<div style="margin-bottom:10px"><b>'+esc(file.name)+'</b></div><label style="display:flex;align-items:center;gap:4px;cursor:pointer;font-size:12px;margin-bottom:10px"><input type="checkbox" id="importCheckAll" onchange="toggleImportCheckAll(this.checked)" checked> 全选 ('+rooms.length+')</label><div id="importRoomChecks">'+rooms.map(function(r){var st=S.spaceTypes.find(function(s){return s.id===r.spaceTypeId});var ex=[];if((r.doors||[]).length)ex.push((r.doors||[]).length+'门');if((r.windows||[]).length)ex.push((r.windows||[]).length+'窗');return '<div class="import-room-check"><label><input type="checkbox" class="import-room-cb" value="'+r.id+'" checked><div class="irc-info"><div class="irc-name">'+(st?st.icon:'')+' '+esc(r.name)+'</div><div class="irc-detail">'+r.area+'㎡ | 周长'+r.perimeter+'m | 高'+r.height+'m'+(ex.length?' | '+ex.join('·'):'')+'</div></div></label></div>'}).join('')+'</div>';openModal('importConfirmModal')}
function toggleImportCheckAll(c){document.querySelectorAll('.import-room-cb').forEach(function(cb){cb.checked=c})}
function doImportRooms(){if(!S.importSelectedFileId)return;var file=S.files.find(function(f){return f.id===S.importSelectedFileId});if(!file)return;var rooms=file.data.rooms||[];var sel=[];document.querySelectorAll('.import-room-cb:checked').forEach(function(cb){sel.push(cb.value)});if(!sel.length){showToast('请选择');return}var n=0;rooms.forEach(function(r){if(sel.indexOf(r.id)===-1)return;var nr={id:uid(),name:r.name,spaceTypeId:r.spaceTypeId,area:r.area,perimeter:r.perimeter,height:r.height,doors:r.doors||[],windows:r.windows||[],hasEquipment:false,hasCustom:!!(r.customItems&&r.customItems.length),hasFeatureWall:false,equipmentItems:[],customItems:[],featureWallItems:[]};if(r.customItems&&r.customItems.length){nr.customItems=r.customItems.map(function(c){var m=S.materials.find(function(x){return x.name===c.name&&x.category==='定制产品'});return{name:c.name,length:c.length,depth:c.depth||0.6,height:c.height,unitPrice:m?m.prices[S.currentPlan]:0}})}S.rooms.push(nr);S.quoteItems=S.quoteItems.concat(generateRoomItems(nr));n++});closeModal('importConfirmModal');renderRoomList();renderQuoteTable();renderSummary();showToast('已导入'+n+'个房间');markDirty()}

