function renderCustomerInfo(){document.getElementById('custName').value=S.customerInfo.name||'';document.getElementById('custPhone').value=S.customerInfo.phone||'';document.getElementById('custAddress').value=S.customerInfo.address||'';document.getElementById('custDesigner').value=S.customerInfo.designer||'';document.getElementById('custDesignerPhone').value=S.customerInfo.designerPhone||'';document.getElementById('custPlan').value=S.currentPlan;document.getElementById('custDate').value=S.customerInfo.date||'';document.getElementById('custArea').value=S.customerInfo.area||''}
function renderRoomList(){var el=document.getElementById('roomList');if(!S.rooms.length){el.innerHTML='<div class="empty-state"><div class="icon">🏠</div><p>点击添加房间</p></div>';return}el.innerHTML=S.rooms.map(function(r){var st=S.spaceTypes.find(function(s){return s.id===r.spaceTypeId});var wa=Math.max(0,r.perimeter*r.height-(r.doors||[]).reduce(function(s,d){return s+d.width*d.height},0)-(r.windows||[]).reduce(function(s,w){return s+w.width*w.height},0));var tags=[];if(r.hasEquipment)tags.push('设备');if(r.hasCustom)tags.push('定制');if(r.hasFeatureWall)tags.push('背景墙');return '<div class="room-item"><div class="room-item-header"><span class="room-item-name">'+(st?st.icon:'')+' '+esc(r.name)+'</span><span class="room-item-type">'+(st?st.name:'')+'</span></div><div class="room-item-dims">面积: '+r.area+'㎡ | 周长: '+r.perimeter+'m | 高: '+r.height+'m</div><div class="room-item-areas"><div class="room-area-tag">地面 <span>'+r.area+'</span>㎡</div><div class="room-area-tag">墙面 <span>'+fmt(wa)+'</span>㎡</div><div class="room-area-tag">顶面 <span>'+r.area+'</span>㎡</div></div>'+(tags.length?'<div class="room-item-tags">'+tags.map(function(t){return'<span class="room-tag">'+t+'</span>'}).join('')+'</div>':'')+'<div class="room-item-actions"><button class="btn btn-outline btn-sm" onclick="editRoom(\''+r.id+'\')">编辑</button><button class="btn btn-danger btn-sm" onclick="deleteRoom(\''+r.id+'\')">删除</button></div></div>'}).join('')}
function dwRow(d){return'<div class="door-win-row"><span>宽</span><input value="'+(d?d.width:'')+'" type="number" step="0.01"><span>× 高</span><input value="'+(d?d.height:'')+'" type="number" step="0.01"><span>m</span><button class="btn-x" onclick="this.parentElement.remove()">×</button></div>'}
function openRoomEditor(rid){S.editingRoomId=rid||null;var r=rid?S.rooms.find(function(x){return x.id===rid}):null;document.getElementById('roomEditorTitle').textContent=r?'编辑房间':'添加房间';var stO=S.spaceTypes.map(function(s){return'<option value="'+s.id+'" '+(r&&r.spaceTypeId===s.id?'selected':'')+'>'+s.icon+' '+s.name+'</option>'}).join('');var eqP=DEFAULT_EQUIPMENT.map(function(e){return'<option value="'+esc(e.name)+'">'+esc(e.name)+' ('+esc(e.brand)+')</option>'}).join('');var cP=['衣柜','电视柜','书柜','橱柜','护墙板','门','踢脚线'].map(function(n){return'<option value="'+n+'">'+n+'</option>'}).join('');document.getElementById('roomEditorBody').innerHTML='<div class="form-grid"><div class="form-group"><label>名称</label><input id="reName" value="'+(r?esc(r.name):'')+'"></div><div class="form-group"><label>空间类型</label><select id="reSpaceType">'+stO+'</select></div><div class="form-group"><label>面积 (㎡)</label><input type="number" id="reArea" value="'+(r?r.area:'')+'" step="0.01"></div><div class="form-group"><label>周长 (m)</label><input type="number" id="rePerimeter" value="'+(r?r.perimeter:'')+'" step="0.01"></div><div class="form-group"><label>高度 (m)</label><input type="number" id="reHeight" value="'+(r?r.height:'')+'" step="0.01"></div></div><div class="sub-section"><h4>门</h4><div id="reDoors">'+(r?(r.doors||[]).map(dwRow).join(''):'')+'</div><button class="btn btn-outline btn-sm" onclick="addDoor()">+ 添加</button></div><div class="sub-section"><h4>窗户</h4><div id="reWindows">'+(r?(r.windows||[]).map(dwRow).join(''):'')+'</div><button class="btn btn-outline btn-sm" onclick="addWindow()">+ 添加</button></div><div class="sub-section"><h4>附加</h4><div class="section-toggle"><label><input type="checkbox" id="reHasEquip" '+(r&&r.hasEquipment?'checked':'')+' onchange="toggleSection(\'Equip\',this.checked)"> 设备</label><label><input type="checkbox" id="reHasCustom" '+(r&&r.hasCustom?'checked':'')+' onchange="toggleSection(\'Custom\',this.checked)"> 定制</label><label><input type="checkbox" id="reHasFeatureWall" '+(r&&r.hasFeatureWall?'checked':'')+' onchange="toggleSection(\'Fw\',this.checked)"> 背景墙</label></div><div id="reEquipSection" style="display:'+(r&&r.hasEquipment?'block':'none')+'"><div style="margin-bottom:6px"><select id="equipPresetSelect"><option value="">预设...</option>'+eqP+'</select> <button class="btn btn-outline btn-sm" onclick="addPresetEquip()">添加</button></div><div id="reEquipItems">'+(r&&r.hasEquipment?(r.equipmentItems||[]).map(equipRow).join(''):'')+'</div><button class="btn btn-outline btn-sm" onclick="addEquipItem()">+ 自定义</button></div><div id="reCustomSection" style="display:'+(r&&r.hasCustom?'block':'none')+'"><div style="margin-bottom:6px"><select id="customPresetSelect"><option value="">预设...</option>'+cP+'</select> <button class="btn btn-outline btn-sm" onclick="addPresetCustom()">添加</button></div><div id="reCustomItems">'+(r&&r.hasCustom?(r.customItems||[]).map(customRow).join(''):'')+'</div><button class="btn btn-outline btn-sm" onclick="addCustomItem()">+ 自定义</button></div><div id="reFwSection" style="display:'+(r&&r.hasFeatureWall?'block':'none')+'"><div id="reFwItems">'+(r&&r.hasFeatureWall?(r.featureWallItems||[]).map(fwRow).join(''):'')+'</div><button class="btn btn-outline btn-sm" onclick="addFwItem()">+ 背景</button></div></div>';openModal('roomEditorModal')}
function addDoor(){var c=document.getElementById('reDoors');var d=document.createElement('div');d.innerHTML=dwRow({});c.appendChild(d.firstElementChild)}function addWindow(){var c=document.getElementById('reWindows');var d=document.createElement('div');d.innerHTML=dwRow({});c.appendChild(d.firstElementChild)}
function equipRow(d){return'<div class="equip-row"><input placeholder="名称" value="'+(d?esc(d.name):'')+'" style="width:100px"><input placeholder="品牌" value="'+(d?esc(d.brand):'')+'" style="width:90px"><input placeholder="单价" value="'+(d?d.unitPrice:'')+'" type="number" style="width:65px"><input placeholder="数量" value="'+(d?d.quantity:1)+'" type="number" style="width:50px"><input placeholder="单位" value="'+(d?esc(d.unit||'项'):'项')+'" style="width:40px"><button class="btn-x" onclick="this.parentElement.remove()">×</button></div>'}
function addEquipItem(){var c=document.getElementById('reEquipItems');var d=document.createElement('div');d.innerHTML=equipRow({});c.appendChild(d.firstElementChild)}
function addPresetEquip(){var s=document.getElementById('equipPresetSelect');if(!s.value)return;var eq=DEFAULT_EQUIPMENT.find(function(e){return e.name===s.value});if(!eq)return;var c=document.getElementById('reEquipItems');var d=document.createElement('div');d.innerHTML=equipRow({name:eq.name,brand:eq.brand,unitPrice:eq.unitPrice,quantity:1,unit:eq.unit});c.appendChild(d.firstElementChild);s.value=''}
function customRow(d){return'<div class="custom-row"><input placeholder="名称" value="'+(d?esc(d.name):'')+'" style="width:90px"><input placeholder="长" value="'+(d?d.length:'')+'" type="number" step="0.01" style="width:60px"><input placeholder="深" value="'+(d?d.depth:'')+'" type="number" step="0.01" style="width:60px"><input placeholder="高" value="'+(d?d.height:'')+'" type="number" step="0.01" style="width:60px"><input placeholder="单价" value="'+(d?d.unitPrice:'')+'" type="number" style="width:60px"><button class="btn-x" onclick="this.parentElement.remove()">×</button></div>'}
function addCustomItem(){var c=document.getElementById('reCustomItems');var d=document.createElement('div');d.innerHTML=customRow({});c.appendChild(d.firstElementChild)}
function addPresetCustom(){var s=document.getElementById('customPresetSelect');if(!s.value)return;var n=s.value;var m=S.materials.find(function(x){return x.name===n&&x.category==='定制产品'});var p=m?m.prices[S.currentPlan]:0;var c=document.getElementById('reCustomItems');var d=document.createElement('div');d.innerHTML=customRow({name:n,length:'',depth:0.6,height:'',unitPrice:p});c.appendChild(d.firstElementChild);s.value=''}
function fwRow(d){return'<div class="fw-row"><input placeholder="名称" value="'+(d?esc(d.name):'')+'" style="width:110px"><input placeholder="面积" value="'+(d?d.area:'')+'" type="number" step="0.01" style="width:70px"><input placeholder="单价" value="'+(d?d.unitPrice:'')+'" type="number" style="width:70px"><button class="btn-x" onclick="this.parentElement.remove()">×</button></div>'}
function addFwItem(){var c=document.getElementById('reFwItems');var d=document.createElement('div');d.innerHTML=fwRow({});c.appendChild(d.firstElementChild)}
function toggleSection(t,c){var s=document.getElementById('re'+t+'Section');if(s)s.style.display=c?'block':'none';var l=document.getElementById('toggle'+t);if(l){if(c)l.classList.add('checked');else l.classList.remove('checked')}}
function editRoom(id){openRoomEditor(id)}
function saveRoom(){var name=document.getElementById('reName').value.trim();var stId=document.getElementById('reSpaceType').value;var area=parseFloat(document.getElementById('reArea').value)||0;var peri=parseFloat(document.getElementById('rePerimeter').value)||0;var h=parseFloat(document.getElementById('reHeight').value)||0;if(!area||!peri||!h){showToast('请输入面积、周长和高度');return}var doors=[],windows=[],eqs=[],cus=[],fws=[];document.querySelectorAll('#reDoors .door-win-row').forEach(function(row){var i=row.querySelectorAll('input');var w=parseFloat(i[0].value)||0,h=parseFloat(i[1].value)||0;if(w&&h)doors.push({width:w,height:h})});document.querySelectorAll('#reWindows .door-win-row').forEach(function(row){var i=row.querySelectorAll('input');var w=parseFloat(i[0].value)||0,h=parseFloat(i[1].value)||0;if(w&&h)windows.push({width:w,height:h})});document.querySelectorAll('#reEquipItems .equip-row').forEach(function(row){var i=row.querySelectorAll('input');if(i[0].value.trim()&&parseFloat(i[2].value))eqs.push({name:i[0].value.trim(),brand:i[1].value.trim(),unitPrice:parseFloat(i[2].value)||0,quantity:parseFloat(i[3].value)||1,unit:i[4].value.trim()||'项'})});document.querySelectorAll('#reCustomItems .custom-row').forEach(function(row){var i=row.querySelectorAll('input');if(i[0].value.trim()&&parseFloat(i[1].value)&&parseFloat(i[3].value))cus.push({name:i[0].value.trim(),length:parseFloat(i[1].value)||0,depth:parseFloat(i[2].value)||0,height:parseFloat(i[3].value)||0,unitPrice:parseFloat(i[4].value)||0})});document.querySelectorAll('#reFwItems .fw-row').forEach(function(row){var i=row.querySelectorAll('input');if(i[0].value.trim()&&parseFloat(i[1].value))fws.push({name:i[0].value.trim(),area:parseFloat(i[1].value)||0,unitPrice:parseFloat(i[2].value)||0})});var st=S.spaceTypes.find(function(s){return s.id===stId});var rd={id:S.editingRoomId||uid(),name:name||(st?st.name:'房间'),spaceTypeId:stId,area:area,perimeter:peri,height:h,doors:doors,windows:windows,hasEquipment:!!eqs.length,hasCustom:!!cus.length,hasFeatureWall:!!fws.length,equipmentItems:eqs,customItems:cus,featureWallItems:fws};if(S.editingRoomId){var idx=S.rooms.findIndex(function(x){return x.id===S.editingRoomId});if(idx>=0)S.rooms[idx]=rd}else S.rooms.push(rd);S.quoteItems=S.quoteItems.filter(function(q){return q.roomId!==rd.id});S.quoteItems=S.quoteItems.concat(generateRoomItems(rd));closeModal('roomEditorModal');renderRoomList();renderQuoteTable();renderSummary();markDirty()}
function deleteRoom(id){if(!confirm('确定删除？'))return;S.rooms=S.rooms.filter(function(r){return r.id!==id});S.quoteItems=S.quoteItems.filter(function(q){return q.roomId!==id});renderRoomList();renderQuoteTable();renderSummary();markDirty()}

// ==================== QUOTE GENERATION ====================
function generateRoomItems(room){var items=[],fa=room.area,ca=room.area,da=(room.doors||[]).reduce(function(s,d){return s+d.width*d.height},0),wa2=(room.windows||[]).reduce(function(s,w){return s+w.width*w.height},0),wa=Math.max(0,room.perimeter*room.height-da-wa2),sk=Math.max(0,room.perimeter-(room.doors||[]).reduce(function(s,d){return s+d.width},0)),ww=(room.windows||[]).reduce(function(s,w){return s+w.width},0),dp=(room.doors||[]).reduce(function(s,d){return s+(d.width+d.height)*2},0),wp=(room.windows||[]).reduce(function(s,w){return s+(w.width+w.height)*2},0),ws=(room.windows||[]).length;
var app=S.materials.filter(function(m){if(m.calcType==='building_area')return false;if(!m.spaceTypeFilter||!m.spaceTypeFilter.length)return true;return m.spaceTypeFilter.includes(room.spaceTypeId)});
app.forEach(function(mat){var qty=0;switch(mat.calcType){case'wall_area':qty=wa;break;case'floor_area':qty=fa;break;case'ceiling_area':qty=ca;break;case'skirting':qty=sk;break;case'door_count':qty=(room.doors||[]).length;break;case'door_perimeter':qty=dp;break;case'window_perimeter':qty=wp;break;case'window_width':qty=ww;break;case'window_sill':qty=ws;break;case'item':qty=1;break}if(qty>0&&mat.prices[S.currentPlan]>0){var desc=mat.description||'';if(mat.processDetail&&mat.processDetail[S.currentPlan])desc=mat.processDetail[S.currentPlan];else if(mat.brand&&mat.brand!=='-')desc+=' | '+mat.brand;items.push({id:uid(),materialId:mat.id,roomId:room.id,name:mat.name,quantity:Math.round(qty*100)/100,unit:mat.unit,unitPrice:mat.prices[S.currentPlan],description:desc,category:mat.category})}});
if(room.hasEquipment)room.equipmentItems.forEach(function(eq){items.push({id:uid(),roomId:room.id,name:eq.name,quantity:eq.quantity,unit:eq.unit||'项',unitPrice:eq.unitPrice,description:eq.brand?'品牌: '+eq.brand:'',category:'设备产品'})});
if(room.hasCustom)room.customItems.forEach(function(cp){items.push({id:uid(),roomId:room.id,name:cp.name,quantity:Math.round(cp.length*cp.height*100)/100,unit:'㎡',unitPrice:cp.unitPrice,description:'尺寸: '+cp.length+'×'+cp.depth+'×'+cp.height+'m',category:'定制产品'})});
if(room.hasFeatureWall)room.featureWallItems.forEach(function(fw){items.push({id:uid(),roomId:room.id,name:fw.name,quantity:fw.area,unit:'㎡',unitPrice:fw.unitPrice,description:'',category:'背景墙'})});
return items}
function regenerateAllQuotes(){S.quoteItems=[];S.rooms.forEach(function(r){S.quoteItems=S.quoteItems.concat(generateRoomItems(r))});regenerateUtilityItems();syncPricesFromMaterials();renderQuoteTable();renderSummary()}
function regenerateUtilityItems(){S.quoteItems=S.quoteItems.filter(function(q){return q.roomId!=='__utility__'});var area=parseFloat(S.customerInfo.area)||0;if(!area)return;S.materials.filter(function(m){return m.calcType==='building_area'}).forEach(function(mat){var qty=area;if(mat.name.includes('开关'))qty=Math.round(area/3);if(mat.prices[S.currentPlan]<=0)return;var desc=mat.description||'';if(mat.processDetail&&mat.processDetail[S.currentPlan])desc=mat.processDetail[S.currentPlan];S.quoteItems.push({id:uid(),materialId:mat.id,roomId:'__utility__',name:mat.name,quantity:Math.round(qty*100)/100,unit:mat.unit,unitPrice:mat.prices[S.currentPlan],description:desc,category:mat.category})})}
function syncPricesFromMaterials(){S.quoteItems.forEach(function(qi){if(qi.materialId){var m=S.materials.find(function(x){return x.id===qi.materialId});if(m&&m.prices[S.currentPlan]>0){qi.unitPrice=m.prices[S.currentPlan];var desc=m.description||'';if(m.processDetail&&m.processDetail[S.currentPlan])desc=m.processDetail[S.currentPlan];else if(m.brand&&m.brand!=='-')desc+=' | '+m.brand;qi.description=desc}}})}

// ==================== QUOTE TABLE ====================
function renderQuoteTable(){var w=document.getElementById('quoteTableWrapper');if(!S.rooms.length&&!S.quoteItems.length&&!S.productQuoteItems.length){w.innerHTML='<div class="empty-state"><div class="icon">📋</div><p>添加房间后自动生成</p></div>';return}
var h='<table class="quote-table"><thead><tr><th class="col-num resizable" data-col="num">序号</th><th class="col-name resizable" data-col="name">项目</th><th class="col-qty resizable" data-col="qty">数量</th><th class="col-unit resizable" data-col="unit">单位</th><th class="col-price resizable" data-col="price">单价</th><th class="col-amount resizable" data-col="amount">金额</th><th class="col-desc resizable" data-col="desc">说明</th><th class="col-action no-print">操作</th></tr></thead><tbody>';var seq=1,catOrd=['拆除工程','砌筑工程','水电工程','防水工程','泥瓦工程','木作工程','油漆工程','墙面工程','地面工程','顶面工程','门窗工程','暖气改造','下水改造','安装工程','楼梯工程','设备产品','定制产品','背景墙'],sg={};S.rooms.forEach(function(r){if(!sg[r.spaceTypeId])sg[r.spaceTypeId]=[];sg[r.spaceTypeId].push(r)});Object.keys(sg).forEach(function(stId){var st=S.spaceTypes.find(function(s){return s.id===stId});var rooms=sg[stId];var si=S.quoteItems.filter(function(q){return rooms.some(function(r){return r.id===q.roomId})});if(!si.length)return;var stT=si.reduce(function(s,q){return s+q.quantity*q.unitPrice},0);h+='<tr class="cat-row"><td colspan="8">'+(st?st.icon:'')+' '+(st?st.name:'')+' <span style="float:right;font-weight:400;color:var(--accent)">¥'+fmt(stT)+'</span></td></tr>';rooms.forEach(function(room){var ri=si.filter(function(q){return q.roomId===room.id});if(!ri.length)return;var rT=ri.reduce(function(s,q){return s+q.quantity*q.unitPrice},0);h+='<tr class="sub-row"><td colspan="8">📍 '+esc(room.name)+' <span style="float:right;font-weight:400;color:var(--accent)">¥'+fmt(rT)+'</span></td></tr>';catOrd.forEach(function(cat){var ci=ri.filter(function(q){return q.category===cat});if(!ci.length)return;var cT=ci.reduce(function(s,q){return s+q.quantity*q.unitPrice},0);h+='<tr><td colspan="7" style="text-align:left;padding-left:20px;font-size:10px;color:var(--text-dim);border-bottom:1px solid var(--border)">▸ '+cat+' <span style="float:right">¥'+fmt(cT)+'</span></td><td class="no-print"></td></tr>';ci.forEach(function(qi){h+=qRow(qi,seq++)})})})});var ui=S.quoteItems.filter(function(q){return q.roomId==='__utility__'});if(ui.length){var uT=ui.reduce(function(s,q){return s+q.quantity*q.unitPrice},0);h+='<tr class="cat-row"><td colspan="8">⚡ 水电暖气下水 <span style="float:right;font-weight:400;color:var(--accent)">¥'+fmt(uT)+'</span></td></tr>';ui.forEach(function(q){h+=qRow(q,seq++)})}var ci=S.quoteItems.filter(function(q){return q.roomId==='__custom__'});if(ci.length){h+='<tr class="cat-row"><td colspan="8">📝 自定义</td></tr>';ci.forEach(function(q){h+=qRow(q,seq++)})}if(S.productQuoteItems.length){PRODUCT_MAIN_CATEGORIES.forEach(function(mc){var pi=S.productQuoteItems.filter(function(q){return q.mainCategory===mc.id});if(!pi.length)return;var pT=pi.reduce(function(s,q){return s+q.quantity*q.unitPrice},0);h+='<tr class="cat-row"><td colspan="8">'+mc.icon+' '+mc.name+' <span style="float:right;font-weight:400;color:var(--accent)">¥'+fmt(pT)+'</span></td></tr>';var subG={};pi.forEach(function(q){if(!subG[q.subCategory])subG[q.subCategory]=[];subG[q.subCategory].push(q)});Object.keys(subG).forEach(function(subId){var subI=subG[subId];var sT=subI.reduce(function(s,q){return s+q.quantity*q.unitPrice},0);h+='<tr><td colspan="7" style="text-align:left;padding-left:20px;font-size:10px;color:var(--text-dim);border-bottom:1px solid var(--border)">▸ '+getSubCatLabel(mc.id,subId)+' <span style="float:right">¥'+fmt(sT)+'</span></td><td class="no-print"></td></tr>';subI.forEach(function(q){h+=qRow(q,seq++)})})})}h+='<tr><td colspan="7" style="text-align:right;padding-right:12px"><button class="btn btn-outline btn-sm no-print" onclick="addCustomQuoteItem()">+ 自定义</button></td><td class="no-print"></td></tr>';h+='</tbody></table>';w.innerHTML=h}
function qRow(qi,seq){var a=qi.quantity*qi.unitPrice;return '<tr><td>'+seq+'</td><td><input class="qt-input qt-name" value="'+esc(qi.name)+'" onchange="updateQI(\''+qi.id+'\',\'name\',this.value)"></td><td><input class="qt-input qt-qty" type="number" value="'+qi.quantity+'" step="0.01" onchange="updateQI(\''+qi.id+'\',\'quantity\',this.value)"></td><td><input class="qt-input qt-unit" value="'+esc(qi.unit)+'" onchange="updateQI(\''+qi.id+'\',\'unit\',this.value)"></td><td><input class="qt-input qt-price" type="number" value="'+qi.unitPrice+'" step="0.01" onchange="updateQI(\''+qi.id+'\',\'unitPrice\',this.value)"></td><td class="col-amount">¥'+fmt(a)+'</td><td><input class="qt-input qt-desc" value="'+esc(qi.description||'')+'" onchange="updateQI(\''+qi.id+'\',\'description\',this.value)"></td><td class="no-print"><button class="btn-x" onclick="deleteQI(\''+qi.id+'\')">×</button></td></tr>'}
function updateQI(id,f,v){var q=S.quoteItems.concat(S.productQuoteItems).find(function(x){return x.id===id});if(!q)return;if(f==='quantity'||f==='unitPrice')q[f]=parseFloat(v)||0;else q[f]=v;renderQuoteTable();renderSummary();markDirty()}
function deleteQI(id){S.quoteItems=S.quoteItems.filter(function(q){return q.id!==id});S.productQuoteItems=S.productQuoteItems.filter(function(q){return q.id!==id});renderQuoteTable();renderSummary();markDirty()}
function addCustomQuoteItem(){S.quoteItems.push({id:uid(),roomId:'__custom__',name:'自定义项目',quantity:1,unit:'项',unitPrice:0,description:'',category:'自定义'});renderQuoteTable();renderSummary();markDirty()}

// ==================== SUMMARY ====================
function renderSummary(){var el=document.getElementById('summarySection');var eT=S.quoteItems.reduce(function(s,i){return s+(i.quantity||0)*(i.unitPrice||0)},0);var pT=S.productQuoteItems.reduce(function(s,i){return s+(i.quantity||0)*(i.unitPrice||0)},0);var sub=eT+pT;var mg=sub*S.managementFeeRate/100;var tx=sub*S.taxRate/100;var g=sub+mg+tx+S.garbageFee+S.protectionFee;var prodBreak='';if(pT>0){PRODUCT_MAIN_CATEGORIES.forEach(function(mc){var t=S.productQuoteItems.filter(function(q){return q.mainCategory===mc.id}).reduce(function(s,q){return s+q.quantity*q.unitPrice},0);if(t>0)prodBreak+='<div class="summary-row"><span class="summary-label" style="padding-left:20px">  '+mc.icon+' '+mc.name+'</span><span class="summary-value">¥'+fmt(t)+'</span></div>'})}el.innerHTML='<div class="summary-row"><span class="summary-label">工程报价</span><span class="summary-value">¥'+fmt(eT)+'</span></div>'+(pT>0?'<div class="summary-row"><span class="summary-label">产品清单</span><span class="summary-value">¥'+fmt(pT)+'</span></div>'+prodBreak:'')+'<div class="summary-row" style="background:var(--accent-dim);padding:10px 14px;border-radius:8px;margin-top:6px"><span class="summary-label" style="font-weight:600">直接费用合计</span><span class="summary-value" style="color:var(--accent)">¥'+fmt(sub)+'</span></div><div class="summary-row"><span class="summary-label">管理费 (<input class="rate-input" value="'+S.managementFeeRate+'" onchange="S.managementFeeRate=parseFloat(this.value)||0;renderSummary()">%)</span><span class="summary-value">¥'+fmt(mg)+'</span></div><div class="summary-row"><span class="summary-label">税金 (<input class="rate-input" value="'+S.taxRate+'" onchange="S.taxRate=parseFloat(this.value)||0;renderSummary()">%)</span><span class="summary-value">¥'+fmt(tx)+'</span></div><div class="summary-row"><span class="summary-label">垃圾清运 <input class="rate-input" value="'+S.garbageFee+'" onchange="S.garbageFee=parseFloat(this.value)||0;renderSummary()"></span><span class="summary-value">¥'+fmt(S.garbageFee)+'</span></div><div class="summary-row"><span class="summary-label">成品保护 <input class="rate-input" value="'+S.protectionFee+'" onchange="S.protectionFee=parseFloat(this.value)||0;renderSummary()"></span><span class="summary-value">¥'+fmt(S.protectionFee)+'</span></div><div class="summary-row total"><span class="summary-label">报价总计</span><span class="summary-value">¥'+fmt(g)+'</span></div>'}

// ==================== MATERIAL/SPACE LIBRARY ====================
function openMaterialLib(){renderMaterialLib();openModal('materialLibModal')}
function renderMaterialLib(){document.getElementById('materialLibBody').innerHTML='<div class="lib-filter"><select id="matCatFilter" onchange="renderMaterialTable()"><option value="">全部</option>'+CATEGORIES.map(function(c){return'<option value="'+c+'">'+c+'</option>'}).join('')+'</select><input id="matSearch" placeholder="搜索..." oninput="renderMaterialTable()"><button class="btn btn-primary btn-sm" onclick="showMaterialForm()">+ 添加</button><button class="btn btn-outline btn-sm" onclick="batchUpdateBrand()">批量改品牌</button></div><div id="matFormArea"></div><div id="matTableArea"></div>';renderMaterialTable()}
function getUniqueBrands(){var b=[];S.materials.forEach(function(m){if(m.brand&&m.brand!=='-'&&b.indexOf(m.brand)===-1)b.push(m.brand)});return b.sort()}
function renderMaterialTable(){var cv=(document.getElementById('matCatFilter')||{}).value;var sr=((document.getElementById('matSearch')||{}).value||'').toLowerCase();var m=S.materials;if(cv)m=m.filter(function(x){return x.category===cv});if(sr)m=m.filter(function(x){return x.name.toLowerCase().includes(sr)||(x.brand||'').toLowerCase().includes(sr)});var el=document.getElementById('matTableArea');if(!m.length){el.innerHTML='<div class="empty-state"><p>暂无</p></div>';return}el.innerHTML='<table class="lib-table"><thead><tr><th>名称</th><th>品牌</th><th>单位</th><th>奢享</th><th>优享</th><th>标准</th><th>分类</th><th>说明</th><th>操作</th></tr></thead><tbody>'+m.map(function(x){return'<tr><td>'+esc(x.name)+'</td><td>'+esc(x.brand)+'</td><td>'+esc(x.unit)+'</td><td>'+(x.prices.luxury||'-')+'</td><td>'+(x.prices.premium||'-')+'</td><td>'+(x.prices.standard||'-')+'</td><td>'+esc(x.category)+'</td><td style="max-width:120px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">'+esc(x.description)+'</td><td><button class="btn btn-outline btn-sm" onclick="editMaterial(\''+x.id+'\')">编辑</button> <button class="btn btn-danger btn-sm" onclick="deleteMaterial(\''+x.id+'\')">删除</button></td></tr>'}).join('')+'</tbody></table>'}
function batchUpdateBrand(){var b=getUniqueBrands();document.getElementById('matFormArea').innerHTML='<div class="mat-form"><div class="form-grid"><div class="form-group"><label>原品牌</label><select id="batchOldBrand">'+b.map(function(x){return'<option>'+esc(x)+'</option>'}).join('')+'</select></div><div class="form-group"><label>新品牌</label><input id="batchNewBrand"></div></div><div style="margin-top:6px"><button class="btn btn-primary btn-sm" onclick="doBatchUpdateBrand()">确认</button></div></div>'}
function doBatchUpdateBrand(){var o=document.getElementById('batchOldBrand').value;var n=document.getElementById('batchNewBrand').value.trim();if(!o||!n)return;var c=0;S.materials.forEach(function(m){if(m.brand===o){m.brand=n;c++}});if(c>0){document.getElementById('matFormArea').innerHTML='';renderMaterialTable();regenerateAllQuotes();saveSettings();showToast('已更新'+c+'个')}else showToast('未找到')}
function showMaterialForm(mat){S.editingMaterialId=mat?mat.id:null;var area=document.getElementById('matFormArea');var stC=S.spaceTypes.map(function(s){return'<label style="font-size:10px;display:inline-flex;align-items:center;gap:2px;margin-right:4px"><input type="checkbox" class="mat-st-filter" value="'+s.id+'" '+(mat&&mat.spaceTypeFilter&&mat.spaceTypeFilter.includes(s.id)?'checked':'')+'>'+s.name+'</label>'}).join('');var pd=mat&&mat.processDetail?mat.processDetail:{luxury:'',premium:'',standard:''};area.innerHTML='<div class="mat-form"><div class="form-grid"><div class="form-group"><label>名称</label><input id="mfName" value="'+(mat?esc(mat.name):'')+'"></div><div class="form-group"><label>品牌</label><input id="mfBrand" value="'+(mat?esc(mat.brand):'')+'"></div><div class="form-group"><label>单位</label><input id="mfUnit" value="'+(mat?esc(mat.unit):'㎡')+'"></div><div class="form-group"><label>分类</label><select id="mfCategory">'+CATEGORIES.map(function(c){return'<option value="'+c+'" '+(mat&&mat.category===c?'selected':'')+'>'+c+'</option>'}).join('')+'</select></div><div class="form-group"><label>计算</label><select id="mfCalcType">'+Object.keys(CALC_TYPES).map(function(k){return'<option value="'+k+'" '+(mat&&mat.calcType===k?'selected':'')+'>'+CALC_TYPES[k]+'</option>'}).join('')+'</select></div><div class="form-group"><label>奢享</label><input type="number" id="mfPL" value="'+(mat?mat.prices.luxury:0)+'"></div><div class="form-group"><label>优享</label><input type="number" id="mfPP" value="'+(mat?mat.prices.premium:0)+'"></div><div class="form-group"><label>标准</label><input type="number" id="mfPS" value="'+(mat?mat.prices.standard:0)+'"></div><div class="form-group full"><label>说明</label><input id="mfDesc" value="'+(mat?esc(mat.description):'')+'"></div><div class="form-group full"><label>奢享工艺</label><input id="mfPDL" value="'+esc(pd.luxury)+'"></div><div class="form-group full"><label>优享工艺</label><input id="mfPDP" value="'+esc(pd.premium)+'"></div><div class="form-group full"><label>标准工艺</label><input id="mfPDS" value="'+esc(pd.standard)+'"></div><div class="form-group full"><label>适用空间</label><div>'+stC+'</div></div></div><div style="margin-top:6px;display:flex;gap:6px"><button class="btn btn-primary btn-sm" onclick="saveMaterial()">保存</button><button class="btn btn-outline btn-sm" onclick="document.getElementById(\'matFormArea\').innerHTML=\'\'">取消</button></div></div>'}
function editMaterial(mid){var m=S.materials.find(function(x){return x.id===mid});if(m)showMaterialForm(m)}
function saveMaterial(){var n=document.getElementById('mfName').value.trim();if(!n){showToast('请输入名称');return}var stF=[];document.querySelectorAll('.mat-st-filter:checked').forEach(function(c){stF.push(c.value)});var d={id:S.editingMaterialId||uid(),name:n,brand:document.getElementById('mfBrand').value.trim(),unit:document.getElementById('mfUnit').value.trim(),prices:{luxury:parseFloat(document.getElementById('mfPL').value)||0,premium:parseFloat(document.getElementById('mfPP').value)||0,standard:parseFloat(document.getElementById('mfPS').value)||0},description:document.getElementById('mfDesc').value.trim(),category:document.getElementById('mfCategory').value,calcType:document.getElementById('mfCalcType').value,spaceTypeFilter:stF,processDetail:{luxury:document.getElementById('mfPDL').value.trim(),premium:document.getElementById('mfPDP').value.trim(),standard:document.getElementById('mfPDS').value.trim()}};if(S.editingMaterialId){var i=S.materials.findIndex(function(x){return x.id===S.editingMaterialId});if(i>=0)S.materials[i]=d}else S.materials.push(d);S.editingMaterialId=null;document.getElementById('matFormArea').innerHTML='';renderMaterialTable();syncPricesFromMaterials();regenerateAllQuotes();saveSettings();showToast('已保存')}
function deleteMaterial(mid){if(!confirm('确定删除？'))return;S.materials=S.materials.filter(function(m){return m.id!==mid});renderMaterialTable();saveSettings()}
function openSpaceTypeLib(){renderSpaceTypeLib();openModal('spaceTypeLibModal')}
function renderSpaceTypeLib(){document.getElementById('spaceTypeLibBody').innerHTML='<div style="margin-bottom:10px"><button class="btn btn-primary btn-sm" onclick="showSpaceTypeForm()">+ 添加</button></div><div id="stListArea"></div>';renderSpaceTypeList()}
function renderSpaceTypeList(){var el=document.getElementById('stListArea');if(!S.spaceTypes.length){el.innerHTML='<div class="empty-state"><p>暂无</p></div>';return}el.innerHTML=S.spaceTypes.map(function(st){return '<div class="st-item"><div class="st-item-header"><span class="st-item-name">'+st.icon+' '+esc(st.name)+'</span><div><button class="btn btn-outline btn-sm" onclick="editSpaceType(\''+st.id+'\')">编辑</button> <button class="btn btn-danger btn-sm" onclick="deleteSpaceType(\''+st.id+'\')">删除</button></div></div></div>'}).join('')}
function showSpaceTypeForm(st){S.editingSpaceTypeId=st?st.id:null;var area=document.getElementById('stListArea');var emojis=['🛋️','🍽️','🛏️','🍳','🚿','🌿','🚪','📐','📚','📦','🏠','🏢','🛁','🎮','👶','👗','🧹','🏋️'];area.innerHTML='<div class="mat-form"><div class="form-grid"><div class="form-group"><label>名称</label><input id="stName" value="'+(st?esc(st.name):'')+'"></div><div class="form-group"><label>图标</label><select id="stIcon">'+emojis.map(function(e){return'<option value="'+e+'" '+(st&&st.icon===e?'selected':'')+'>'+e+'</option>'}).join('')+'</select></div></div><div style="margin-top:6px;display:flex;gap:6px"><button class="btn btn-primary btn-sm" onclick="saveSpaceType()">保存</button><button class="btn btn-outline btn-sm" onclick="renderSpaceTypeList()">取消</button></div></div>'}
function editSpaceType(id){var st=S.spaceTypes.find(function(s){return s.id===id});if(st)showSpaceTypeForm(st)}
function saveSpaceType(){var n=document.getElementById('stName').value.trim();if(!n)return;var d={id:S.editingSpaceTypeId||uid(),name:n,icon:document.getElementById('stIcon').value};if(S.editingSpaceTypeId){var i=S.spaceTypes.findIndex(function(s){return s.id===S.editingSpaceTypeId});if(i>=0)S.spaceTypes[i]=d}else S.spaceTypes.push(d);S.editingSpaceTypeId=null;renderSpaceTypeList();saveSettings()}
function deleteSpaceType(id){if(!confirm('确定删除？'))return;S.spaceTypes=S.spaceTypes.filter(function(s){return s.id!==id});renderSpaceTypeList();saveSettings()}

