function toggleWatermark(){S.watermarkEnabled=!S.watermarkEnabled;var btn=document.getElementById('watermarkBtn');if(btn)btn.textContent=S.watermarkEnabled?'水印: 开':'水印';saveSettings();showToast(S.watermarkEnabled?'已开启':'已关闭')}

