loadState();setTheme(S.currentTheme);renderSidebar();showView('welcome');
if(typeof LOGO_BASE64==='string'){document.getElementById('headerLogo').src=LOGO_BASE64;document.getElementById('welcomeLogo').src=LOGO_BASE64}
if(S.recentFileIds.length>0){var last=S.files.find(function(f){return f.id===S.recentFileIds[0]});if(last)openFile(last.id)}
document.addEventListener('keydown',function(e){if(e.ctrlKey&&e.key==='s'){e.preventDefault();saveCurrentFile()}});
